export const chunk0: Poem[] = [
  { id: 1, title: "关雎",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "关关雎鸠，在河之洲，窈窕淑女，君子好逑",
    tags: "诗经,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "关雎", original: `关关雎鸠，在河之洲。窈窕淑女，君子好逑。
参差荇菜，左右流之。窈窕淑女，寤寐求之。
求之不得，寤寐思服。悠哉悠哉，辗转反侧。
参差荇菜，左右采之。窈窕淑女，琴瑟友之。
参差荇菜，左右芼之。窈窕淑女，钟鼓乐之。`, translation: `雎鸠鸟叽叽喳喳地叫，在河中小岛上。那美丽善良的好姑娘，正是小伙子的好对象。
水里的荇菜长长短短，有人左右来回地捞。那美丽善良的好姑娘，醒来睡去都想追求她。
追求她却得不到，白天黑夜心里总挂念。长长的思念啊，躺在床上翻来覆去睡不着。
水里的荇菜长长短短，有人左右把菜采。那美丽善良的好姑娘，我要弹琴鼓瑟亲近她。
水里的荇菜长长短短，有人左右把菜摘。那美丽善良的好姑娘，我要敲钟打鼓让她开心。`, interpretation: `《关雎》是《诗经》的开篇之作，距今已有两千多年，是我国最早的诗歌总集里的第一首。那时候的人们用简单纯朴的歌声表达感情。诗中有一个特别有趣的小细节：雎鸠鸟。这种鸟总是成双成对地生活，古人看见它们恩爱的样子，就想到了人间美好的爱情。整首诗最妙的地方在于"求之不得，寤寐思服。悠哉悠哉，辗转反侧"——喜欢一个人却得不到，夜里翻来覆去睡不着，这种感觉两千年前的少年和今天的你，是不是一模一样呢？最后，小伙子想出了办法：用琴瑟、钟鼓去亲近心爱的姑娘，让爱情变得热闹又美好。这首温柔的小诗，就这样一代代传了下来。` }] },
  { id: 2, title: "蒹葭",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "蒹葭苍苍，白露为霜，所谓伊人，在水一方",
    tags: "诗经,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "蒹葭", original: `蒹葭苍苍，白露为霜。所谓伊人，在水一方。溯洄从之，道阻且长。溯游从之，宛在水中央。
蒹葭萋萋，白露未晞。所谓伊人，在水之湄。溯洄从之，道阻且跻。溯游从之，宛在水中坻。
蒹葭采采，白露未已。所谓伊人，在水之涘。溯洄从之，道阻且右。溯游从之，宛在沚。`, translation: `芦苇青青又苍苍，露水变成了白霜。我心里想念的那个人，就在河水的那一边。逆着水流去找她，路又远又难走；顺着水流去找她，她好像就在河水中间。芦苇长得真茂盛，露水还没干呢。我心里想念的那个人，就在水草边。逆着水流去找她，路又远又高；顺着水流去找她，她好像就在水中的小岛上。`, interpretation: `这是两千多年前《诗经》里的一首小歌，写的是秋天清晨，芦苇上挂着白霜，一位小伙子站在河边想念他心爱的姑娘。隔着一条河，看得见却到不了，越追越觉得她飘忽不定——这就是诗里最迷人的“伊人”意象。整首诗三次重复“溯洄”“溯游”，像是在说：明知道够不着，却还是想去找。这份执着的思念，后来成了中国人表达“求而不得”的经典名句，影响了无数诗词。` }] },
  { id: 3, title: "采薇（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "昔我往矣，杨柳依依，今我来思，雨雪霏霏",
    tags: "诗经,战争",
    color: "#d97706",
    sections:[    { id: 1, title: "采薇（节选）", original: `昔我往矣，杨柳依依。今我来思，雨雪霏霏。
行道迟迟，载渴载饥。我心伤悲，莫知我哀。`, translation: `回想当初我离家远行的时候，杨柳随风轻轻飘荡，好像在跟我告别。现在我终于回来了，眼前却是雪花纷纷飘落。走起路来慢慢腾腾，又渴又饿真是难熬。我的心里好悲伤，可没有人明白我的苦啊。`, interpretation: `这首诗出自《诗经》，大约写于两千多年前的西周时期。当时周朝经常和外族打仗，许多士兵被迫离开家乡，一去就是好多年。这段话是一位老兵回家路上的心声——他想起离家时春天杨柳轻柔的模样，对比现在归来时漫天风雪的凄凉，路又远又累，心里满是委屈，可跟谁说呢？短短几句，有景有情，特别是“杨柳依依”和“雨雪霏霏”两个画面，一美一惨，对比强烈，成了千古名句。后来人们写离别、写思乡，常常会想起这两句呢！` }] },
  { id: 4, title: "桃夭",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "桃之夭夭，灼灼其华，之子于归，宜其室家",
    tags: "诗经,婚嫁",
    color: "#d97706",
    sections:[    { id: 1, title: "桃夭", original: `桃之夭夭，灼灼其华。之子于归，宜其室家。
桃之夭夭，有蕡其实。之子于归，宜其家室。
桃之夭夭，其叶蓁蓁。之子于归，宜其家人。`, translation: `桃树长得真年轻啊，开出的花朵红艳艳亮堂堂。这个姑娘要出嫁啦，和和美美一家人！桃树长得真年轻啊，枝头果实肥又大。这个姑娘要出嫁啦，全家和睦乐开花！桃树长得真年轻啊，树叶茂盛密麻麻。这个姑娘要出嫁啦，婆家老少都爱她！`, interpretation: `这首诗来自两千多年前的《诗经》，是古人在婚礼上唱的祝福歌。那时候没有鲜花和彩带，人们就指着院子里盛开的桃树，为新娘送上最美的祝愿。诗里反复写桃树——桃花鲜红、果实饱满、绿叶繁茂，象征新娘青春美丽、多子多福、家庭兴旺。整首诗只有短短几句话，却有四组重叠，读起来像欢快的歌声，特别适合婚礼上一起唱。它是中国最早祝贺新娘的诗，后来人们说'桃之夭夭，灼灼其华'，都用来形容春天和美丽的事物呢！` }] },
  { id: 5, title: "静女",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "静女其姝俟我于城隅爱而不见搔首踟蹰",
    tags: "诗经,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "静女", original: `静女其姝，俟我于城隅。爱而不见，搔首踟蹰。
静女其娈，贻我彤管。彤管有炜，说怿女美。
自牧归荑，洵美且异。匪女之为美，美人之贻。`, translation: `温柔漂亮的姑娘啊，约我等在城墙角。
她故意躲起来不露面，让我挠着头来回走。
温柔漂亮的姑娘啊，送我一支红红的笛管。
红笛颜色亮晶晶，我呀越看越喜欢。
她从郊外采来嫩茅草送我，这草儿真美丽又稀奇。
并不是茅草有多好，只因为它是美人亲手送我的。`, interpretation: `这首诗来自两千多年前的《诗经》年代，那时候的年轻人也会偷偷约会呢！全诗讲了一个甜蜜的小故事：一位漂亮的姑娘和小伙子约好在城墙边见面，结果姑娘调皮地藏了起来，小伙子急得抓耳挠腮。姑娘出现后，送了他一支红笛管和一根野草，这些在别人看来普通的小东西，因为是心爱之人送的，就变得无比珍贵啦！诗中最妙的就是最后那句'匪女之为美，美人之贻'——东西好不好不重要，重要的是谁给的。这种'礼物因为心意而珍贵'的想法，到现在还常常被人们说起，是中国最早的'爱情小品文'之一，读起来就像在看一出可爱的古代偶像剧！` }] },
  { id: 6, title: "子衿",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "青青子衿悠悠我心纵我不往子宁不嗣音",
    tags: "诗经,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "子衿", original: `青青子衿，悠悠我心。纵我不往，子宁不嗣音？
青青子佩，悠悠我思。纵我不往，子宁不来？
挑兮达兮，在城阙兮。一日不见，如三月兮`, translation: `你那青青的衣领啊，悠悠地挂在我心头。纵然我今天没去找你，你怎么能就不给我捎个信儿呢？你那青青的佩玉啊，悠悠地让我思念不已。纵然我今天没去找你，你怎么能就不来看我呢？我独自走来走去啊，就在那高高的城楼上张望。一天没见到你啊，就像隔了三个月那么漫长！`, interpretation: `这首诗出自两千多年前的《诗经》，是一位姑娘在等心上人时唱的歌。那时候的女孩子思念情郎，会跑到城楼上去张望，越等越心焦。诗里用'青青'形容衣领和佩玉，色彩明亮又温柔，读着就好像看到了那位翩翩少年。'一日不见，如三月兮'是千古名句，把等待的滋味写得特别传神——才一天没见，感觉比三个月还久呢！小朋友，你有没有过等一个人、等得很焦急的时候？那就懂这位姑娘的心情啦！` }] },
  { id: 7, title: "无衣",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "岂曰无衣，与子同袍，王于兴师，修我戈矛，与子同仇",
    tags: "诗经,战争",
    color: "#d97706",
    sections:[    { id: 1, title: "无衣", original: `岂曰无衣？与子同袍。王于兴师，修我戈矛。与子同仇。
岂曰无衣？与子同泽。王于兴师，修我矛戟。与子偕作。
岂曰无衣？与子同裳。王于兴师，修我甲兵。与子偕行。`, translation: `谁说我们没有衣裳？我和你披同一件战袍！国王要出兵打仗了，快把我们的戈和矛修好，我和你一起对付敌人！谁说我们没有衣裳？我和你穿同一件内衣！国王要出兵打仗了，快把我们的矛和戟修好，我和你一起行动！谁说我们没有衣裳？我和你穿同一条下裳！国王要出兵打仗了，快把我们的铠甲和兵器修好，我和你一起上战场！`, interpretation: `这首诗来自两千多年前的《诗经》，是秦国的一首军歌。当时战乱频繁，百姓要上战场打仗，战士们之间结下了深厚的情谊。诗中反复吟唱'与子同袍''与子同泽''与子同裳'，'袍、泽、裳'是贴身的衣物，说明战士们亲如兄弟、同生共死。最有趣的是它的问答结构——先说'谁说没衣穿'，马上回答'我和你共用'，特别有气势！这首战歌短小有力，读起来像激昂的口号，后来很多诗人都受到它的影响，比如那句'与子同袍'，至今还被人们用来形容朋友间的深厚情谊呢！` }] },
  { id: 8, title: "氓（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "氓之蚩蚩，抱布贸丝，匪来贸丝，来即我谋",
    tags: "诗经,叙事",
    color: "#d97706",
    sections:[    { id: 1, title: "氓（节选）", original: `氓之蚩蚩，抱布贸丝。匪来贸丝，来即我谋。
送子涉淇，至于顿丘。匪我愆期，子无良媒。
桑之未落，其叶沃若。于嗟鸠兮，无食桑葚。
于嗟女兮，无与士耽。士之耽兮，犹可说也。
女之耽兮，不可说也`, translation: `那个男人笑嘻嘻的，抱着布来换我的丝。他哪里是来换丝啊，分明是来找我商量婚事的。我送你渡过淇水，一直送到顿丘。不是我拖延婚期，是你没有找好媒人。桑树叶子还没落的时候，叶子绿油油、水灵灵的。哎呀，斑鸠啊，可别贪吃桑葚！哎呀，姑娘啊，可别对男人太迷恋！男人要是迷上了你，还能脱身；姑娘要是迷上了他，可就难摆脱啦！`, interpretation: `这首诗来自两千多年前的《诗经》，讲的是一个姑娘回忆自己被负心汉欺骗的故事。那时候女孩子不能自己找对象，全靠媒人牵线，规矩可严啦！姑娘用斑鸠吃桑葚会醉倒来打比方，温柔地提醒其他女孩：爱情里要清醒呀！这是中国最早的“弃妇诗”，语言像唱歌一样好听，比喻新鲜又贴切，连后来写《长恨歌》的白居易，都从这儿学了不少表达情感的技巧呢！` }] },
  { id: 9, title: "击鼓（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "死生契阔，与子成说，执子之手，与子偕老",
    tags: "诗经,战争",
    color: "#d97706",
    sections:[    { id: 1, title: "击鼓（节选）", original: `击鼓其镗，踊跃用兵。土国城漕，我独南行。
死生契阔，与子成说。执子之手，与子偕老。
于嗟阔兮，不我活兮`, translation: `战鼓敲得咚咚响，士兵们奋勇练刀枪。修筑漕城保家乡，唯独我被派往南方。生死分离聚散无常，当初和你立下誓言：牵着你的手，和你一起白头到老。唉，如今你我相隔太远，让我活不下去啊！`, interpretation: `这首诗来自两千多年前的春秋时期，写的正是普通士兵远征时的哭诉。那时候战乱频繁，战士们被迫离开家乡和亲人。诗中最打动人的，就是'死生契阔，与子成说。执子之手，与子偕老'这十六个字——它本来是战士对妻子的誓言，却成了中国人对爱情最美好的承诺，千百年来被无数人传诵。短短几句，没有华丽辞藻，却让人读得眼眶发酸，这就是《诗经》的魅力。` }] },
  { id: 10, title: "黍离（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "彼黍离离彼稷之苗知我者谓我心忧不知我者谓我何求",
    tags: "诗经,感怀",
    color: "#d97706",
    sections:[    { id: 1, title: "黍离（节选）", original: `彼黍离离，彼稷之苗。行迈靡靡，中心摇摇。
知我者，谓我心忧。不知我者，谓我何求。
悠悠苍天，此何人哉`, translation: `你看那小米长得一排排，你看那高粱苗儿正青葱。我慢悠悠地往前走啊，心里却乱得像在风中晃。大家懂我的人啊，知道我心里有忧愁。不懂我的人啊，还以为我在找什么。苍天啊高高远远，是谁让我这么难受？`, interpretation: `这首诗来自两千多年前的西周，那时候周王朝被犬戎攻破都城镐京，迁都洛阳。有一位大夫路过旧都宗庙，看到曾经种粮食的田地全长满了野草，心里特别难受，就写下了这首诗。诗里最妙的就是'黍'和'稷'，就是小米和高粱，本来是种给人吃的粮食，现在却乱蓬蓬地长着没人管，好像在悄悄说：这里的人去哪儿了？'中心摇摇'四个字特别传神，'摇摇'就是心里七上八下、晃晃悠悠的意思，比说'我很伤心'生动多了。后来人们说的'黍离之悲'，就是从这儿来的，专门指对故国、故都的怀念。` }] },
  { id: 11, title: "离骚（节选）",
    author: "屈原",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "路漫漫其修远兮，吾将上下而求索",
    tags: "楚辞,经典",
    color: "#d97706",
    sections:[    { id: 1, title: "离骚（节选）", original: `长太息以掩涕兮，哀民生之多艰。
亦余心之所善兮，虽九死其犹未悔。
路漫漫其修远兮，吾将上下而求索`, translation: `我长长地叹着气，擦去脸上的泪水。可怜老百姓的生活，充满了艰难和辛酸啊！只要是我真心喜欢的品格，哪怕死上九回，我也不会后悔。前面的路啊，又长又远，我还要继续努力去追求！`, interpretation: `这两句出自屈原的《离骚》。屈原生活在战国时期的楚国，当时朝廷奸臣当道，百姓生活困苦。他虽然被流放，却依然忧国忧民。"太息掩涕"写出了诗人对人民苦难的深深同情，"九死未悔"表现了他坚持理想、绝不妥协的高尚品格。这句话常被后人引用，成为形容执着追求理想的经典名句。` }] },
  { id: 12, title: "湘夫人（节选）",
    author: "屈原",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "袅袅兮，秋风洞庭波兮",
    tags: "楚辞,神话",
    color: "#d97706",
    sections:[    { id: 1, title: "湘夫人（节选）", original: `帝子降兮，北渚。
目眇眇兮，愁予。
袅袅兮秋风，洞庭波兮木叶下。
沅有芷兮，澧有兰。
思公子兮，未敢言`, translation: `公主降临在北面的沙洲上啊，我远远望见她，眼里满是忧伤。秋风轻轻吹起洞庭湖的波浪，落叶纷纷飘下。沅水边长着香草白芷啊，澧水边盛开着幽兰。我深深地想念着你啊，公子！`, interpretation: `这是战国时期楚国大诗人屈原写的《九歌》中的一篇，传说楚地百姓祭祀湘水神时所唱的歌。诗中的湘夫人是传说中舜帝的两个妃子——娥皇和女英，她们泪染青竹，成了湘水之神。诗里写秋风、落叶、白芷、幽兰，处处透着一种凄美又浪漫的气息。屈原最厉害的地方，就是把神话故事和自然景色揉在一起，让人读着读着，就像走进了一幅画。这首诗里'袅袅兮秋风，洞庭波兮木叶下'特别有名，连李白都忍不住模仿它呢！` }] },
  { id: 13, title: "橘颂（节选）",
    author: "屈原",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "后皇嘉树橘徕服兮，受命不迁生南国兮，苏世独立横而不流兮",
    tags: "楚辞,咏物",
    color: "#d97706",
    sections:[    { id: 1, title: "橘颂（节选）", original: `后皇嘉树，橘徕服兮。
受命不迁，生南国兮。
深固难徙，更壹志兮。
绿叶素荣，纷其可喜兮。
苏世独立，横而不流兮`, translation: `天地间美好的橘树啊，生来就适应这片土地。它接受了天命的安排，永远扎根在南方，绝不迁移。根深叶茂，难以移植，志向专一坚定。绿色的叶子，洁白的花朵，繁盛美丽真让人喜爱。它清醒地独立于世，横立水中却不被冲走改变方向。`, interpretation: `这首诗是屈原年轻时的作品，写于楚国（大约现在的湖南、湖北一带）。当时楚国盛产橘子，屈原借橘树来表达自己志向。《橘颂》是中国文学史上第一篇完整的咏物诗，'后皇嘉树'四字奠定了橘树的高洁形象。他写橘树的'深固难徙'、'苏世独立'，其实是在说自己要做一个品行坚定、清醒独立的人。后世许多诗人都从这首诗里学到了'借物言志'的写法，比如曹植的《七步诗》就受其影响。整首诗读起来，就像一个小朋友在认真介绍自己的好朋友呢！` }] },
  { id: 14, title: "国殇（节选）",
    author: "屈原",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "诚既勇兮，又以武终刚强兮，不可凌身既死兮，神以灵魂魄毅兮",
    tags: "楚辞,战争",
    color: "#d97706",
    sections:[    { id: 1, title: "国殇（节选）", original: `操吴戈兮，被犀甲。
车错毂兮，短兵接。
旌蔽日兮，敌若云。
矢交坠兮，士争先。
诚既勇兮，又以武终。
刚强兮，不可凌。
身既死兮，神以灵。
魂魄毅兮，为鬼雄`, translation: `手持锋利的吴戈啊，身披坚固的犀牛甲。战车轮毂交错在一起啊，短兵器相接敌我厮杀。大旗遮蔽了太阳啊，敌人像云一样涌来。乱箭纷纷坠落啊，战士们个个奋勇争先。真是既勇敢啊，又有武力，性情始终刚强啊，敌人不可欺凌。身体已经死去啊，精神依然不灭。魂魄坚毅啊，永不消亡。`, interpretation: `这首诗是屈原为楚国牺牲的将士们写的一首英雄赞歌，写在战国时期楚国战败之后。诗中有两个特别有气势的意象：一个是“旌蔽日”，大旗多得把太阳都遮住了，说明军队人数众多；一个是“敌若云”，敌人像乌云一样密密麻麻压过来，写出了战斗的紧张可怕。这首《国殇》最大的艺术特色是节奏感很强，句子短而有力，读起来像战鼓一样咚咚响，让人热血沸腾。后来人们常用“国殇”来指代为国牺牲的英雄，这首诗也成为祭祀英烈时最常被朗诵的作品。` }] },
  { id: 15, title: "易水歌",
    author: "荆轲",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "风萧萧兮，易水寒壮士一去兮",
    tags: "先秦,经典",
    color: "#d97706",
    sections:[    { id: 1, title: "易水歌", original: `风萧萧兮易水寒，
壮士一去兮不复还`, translation: `风呼呼地吹啊，易水又冷又寒，壮士这一走啊，就再也不会回来啦。`, interpretation: `这是两千多年前战国末年的故事。燕国太子丹派刺客荆轲去秦国行刺暴君嬴政，临走前大家都来送行。荆轲在高台上唱起这首歌，易水河边秋风凛冽，他明知此去凶多吉少，却毫不退缩。这两句一写冷风寒水，一写壮士豪情，用“萧萧”形容风声，仿佛连天地都在为他送别。后人常用“风萧萧兮易水寒”形容悲壮豪迈的离别场景，连大英雄项羽都从中借用了这种气势呢！` }] },
  { id: 16, title: "越人歌",
    author: "佚名",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "山有木兮，木有枝心悦君兮",
    tags: "先秦,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "越人歌", original: `今夕何夕兮，搴舟中流。
今日何日兮，得与王子同舟。
蒙羞被好兮，不訾诟耻。
心几烦而不绝兮，得知王子。
山有木兮木有枝，心悦君兮君不知`, translation: `今天是什么好日子呀，我划船到河中央；今天是什么好日子呀，我竟然能和你这位王子同坐一条船。山上有树呀，树上有枝丫；我心里喜欢你呀，可你却不知道呢。`, interpretation: `这首诗来自遥远的春秋战国时期，是一位划船的越族姑娘唱给楚国王子听的歌，是中国最早的情诗之一。姑娘用山和树打比方——山上有树，树上有枝，这是大家都知道的事；可我喜欢你，你却不知道，多让人着急呀！这种"明明很简单，旁人一看就懂，唯独当事人不知道"的小心思，是不是很像你偷偷喜欢班上的某个同学？全诗只有四句，却把少女怦然心动、想表白又不敢说的小委屈写得特别动人。两千多年过去了，现在我们说"山有木兮木有枝"，大家还是会想起这个勇敢又害羞的越国姑娘。` }] },
  { id: 17, title: "击壤歌",
    author: "佚名",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "日出而作日入而息凿井而饮耕田而食帝力于我何有哉",
    tags: "先秦,民歌",
    color: "#d97706",
    sections:[    { id: 1, title: "击壤歌", original: `日出而作，日入而息。
凿井而饮，耕田而食。
帝力于我何有哉`, translation: `太阳出来了，就出门干活；太阳落山了，就回家休息。在地上挖口井，就能喝上清凉的水；亲手种庄稼，就能吃上香喷喷的饭。帝王有什么了不起的，跟我有什么关系呢？`, interpretation: `这是流传了两千多年的古老民歌，据说是一位老人在田间边唱歌边用木块打着节拍，所以叫《击壤歌》。它诞生在很遥远的先秦时期，那时候普通人过着简单纯朴的日子，歌词里“日出”“日入”“凿井”“耕田”这些画面，就像一幅农家生活图，特别亲切。最有意思的是最后一句“帝力于我何有哉”，意思是我靠自己劳动就能吃饱喝足，帝王跟我有啥关系呢？这句话里藏着一股子自豪和自由劲儿，后世很多人读到都会心一笑，觉得这老头真酷！所以它也被看作中国最早表达平民自得其乐、不慕权贵的诗篇之一。` }] },
  { id: 18, title: "卿云歌",
    author: "佚名",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "卿云烂兮，纠缦缦兮，日月光华旦复旦兮",
    tags: "先秦,颂歌",
    color: "#d97706",
    sections:[    { id: 1, title: "卿云歌", original: `卿云烂兮，纠缦缦兮。
日月光华，旦复旦兮`, translation: `看那五彩云霞多绚丽啊，云层层层叠叠舒卷漫延啊！太阳和月亮的光辉照耀大地，一天接着一天，永远明亮不停歇啊！`, interpretation: `这首歌传说是上古时代虞舜在位时，君臣齐唱的歌谣，距今已有四千多年啦！它描绘了天空中华丽的彩云和灿烂的日月，表达了对太平盛世的赞美与祝福。短短三句话里，云、光、日、月交织成一幅明亮祥和的画面，节奏明快，读起来朗朗上口。后来人们常说的“日月光华”“复旦”这些词都从这里来的，意思是光明不断重现，美好永远延续。这首歌也入选了语文课本，是小朋友们认识上古诗歌的好起点哦！` }] },
  { id: 19, title: "天问（节选）",
    author: "屈原",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "遂古之初，谁传道之，上下未形，何由考之",
    tags: "楚辞,哲理",
    color: "#d97706",
    sections:[    { id: 1, title: "天问（节选）", original: `遂古之初，谁传道之？
上下未形，何由考之？
冥昭瞢暗，谁能极之？
明明暗暗，惟时何为？
阴阳三合，何本何化？
圆则九重，孰营度之？`, translation: `远古最开始的时候，是谁把那些事情传说讲述？天和地还没有成形，那时候的情况怎么去考察清楚？天地一片混沌昏暗，谁能够追根究底问个明白？光明和黑暗交替出现，这到底是因为什么？阴阳二气融合在一起，哪个是本源，哪个又变成了这样？`, interpretation: `这首诗来自两千多年前战国时期的楚国，是大诗人屈原写的《天问》。那时候的人们对天地宇宙充满好奇，却又没有科学答案。屈原就像一个爱提问的小学生，对着苍天一口气问了很多大问题——天是谁造的？地是怎么来的？白天黑夜为什么交替？这些奇思妙想后来被称作'天问'，连大文豪鲁迅都称赞，说屈原敢向天发问，脑子真厉害！这首诗里的'冥昭瞢暗'四个字特别形象，写出了天地未分时那种又暗又亮、模模糊糊的样子。屈原这种爱思考、爱追问的精神，一直影响到今天，我们每个人都可以像他一样，做一个勇敢的'小问号'！` }] },
  { id: 20, title: "河广",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "谁谓河广，一苇杭之，谁谓宋远，跂予望之",
    tags: "诗经,思乡",
    color: "#d97706",
    sections:[    { id: 1, title: "河广", original: `谁谓河广？一苇杭之。
谁谓宋远？跂予望之。
谁谓河广？曾不容刀。
谁谓宋远？曾不崇朝`, translation: `谁说黄河宽又宽？一根芦苇就能渡过去。谁说宋国路很远？踮起脚尖就能望见。谁说黄河宽又宽？它其实窄得连小船都容不下。谁说宋国路很远？走一个早晨就能到。`, interpretation: `这首诗来自两千多年前的《诗经》，是一位住在卫国的人思念家乡宋国时写的。他心里太想家了，所以觉得黄河根本不宽，宋国根本不远。其实呀，黄河又宽又深，宋国也隔着千山万水呢！诗里用了一连串的反问“谁谓”，像是在跟人争辩，特别有童趣。叠句和反问的写法让思乡之情又急切又可爱，也让我们看到：想家的时候，距离好像都能被爱拉近。这首小诗虽然短，却被后人传诵了两千多年呢。` }] },
  { id: 21, title: "君子于役",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "君子于役，不知其期，鸡栖于埘，日之夕矣，羊牛下来",
    tags: "诗经,思念",
    color: "#d97706",
    sections:[    { id: 1, title: "君子于役", original: `君子于役，不知其期。
曷至哉？鸡栖于埘。
日之夕矣，羊牛下来。
君子于役，如之何勿思`, translation: `丈夫在外面服役，不知道什么时候才能回来。鸡已经飞回窝里休息，太阳也快要落山了。羊儿和牛儿都从山上回来了。丈夫还在外面服役，叫我怎么能不想念他呢？`, interpretation: `这首诗来自两千多年前的春秋时期，那时候男子要去远方服兵役或劳役，一去就不知道什么时候能回家。诗中一位女子在傍晚时分，看着鸡回窝、牛羊下山的景象，心里特别想念远方的丈夫。傍晚是回家团聚的时刻，可她的丈夫不在身边，这让她更觉得孤单。最有意思的是，诗里没有直接说'我很想他'，而是通过描写鸡、牛、羊都回家了，反衬出丈夫还没归来的遗憾，这就是古诗常用的'反衬'手法。读起来亲切温柔，像是我们自己的妈妈在门口盼着爸爸下班回来一样，让人心里暖暖的又酸酸的。` }] },
  { id: 22, title: "木瓜",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "投我以木瓜报之以琼琚匪报也永以为好也",
    tags: "诗经,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "木瓜", original: `投我以木瓜，报之以琼琚。
匪报也，永以为好也。
投我以木桃，报之以琼瑶。
匪报也，永以为好也。
投我以木李，报之以琼玖。
匪报也，永以为好也`, translation: `你送我一个木瓜,我拿美玉佩饰来报答你。这不是简单的回礼啊,是希望我们永远相好呀!你送我蜜桃,我拿美玉来回报。这不是答谢你,是愿咱们情谊长久呀!`, interpretation: `这首诗来自两千多年前的《诗经》,是古代青年男女互赠定情信物时唱的歌。姑娘送小伙子木瓜、桃子这样普通的水果,小伙子却回赠珍贵的美玉——这说明在他心中,姑娘的情意比美玉还宝贵呀!诗中最有意思的地方是"匪报也"三个字,意思是"这哪里是报答"。古人不像我们现在说话这么直白,他们用反复吟唱"永以为好也"来表达心意,既含蓄又深情。后来"投桃报李"这个成语就是从这儿来的,比喻朋友之间互相赠送礼物、礼尚往来。读这首诗的时候,你能感受到古人表达爱情的方式多么温柔又真诚呢!` }] },
  { id: 23, title: "采葛",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "彼采葛兮，一日不见如三月兮",
    tags: "诗经,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "采葛", original: `彼采葛兮，一日不见如三月兮。
彼采萧兮，一日不见如三秋兮。
彼采艾兮，一日不见如三岁兮。`, translation: `那个采葛的姑娘啊，一天见不到她，好像隔了三个月那么久！那个采萧的姑娘啊，一天见不到她，好像隔了三个季度那么久！那个采艾草的姑娘啊，一天见不到她，好像隔了整整三年那么久！`, interpretation: `这首诗来自两千多年前的春秋时期，是一位小伙子在唱给心上人听的歌。那时候人们采集葛草、萧草、艾草来生活，小伙子借这些常见的事儿来想念那个采草的姑娘。他用“一天不见”开头，却越说越长——三个月、三季、三年，时间像被想念拉长了一样！这就叫“夸张”，越夸张越说明想得厉害。整首诗只有几句话，却把热恋中“度日如年”的心情写活了，后来人们形容思念特别深，还常常会想到这首诗呢。` }] },
  { id: 24, title: "月出",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "月出皎兮，佼人僚兮，舒窈纠兮，劳心悄兮",
    tags: "诗经,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "月出", original: `月出皎兮，佼人僚兮，舒窈纠兮，劳心悄兮。
月出皓兮，佼人懰兮，舒忧受兮，劳心慅兮。`, translation: `月亮出来亮堂堂啊，那位美人真漂亮啊。身姿轻盈又苗条啊，我的心儿好忧伤啊。月亮出来多明亮啊，那位美人真秀丽啊。体态舒缓又柔美啊，我的心儿乱晃晃啊。`, interpretation: `这首诗来自两千多年前的《诗经·陈风》，是古人写给心上人的"小情歌"。皎洁的月光下，诗人偷偷望着美丽的姑娘，越看越喜欢，心里却像小鹿乱撞，又甜又慌。诗中最妙的就是"月出"和"美人"交相辉映——月亮越亮，姑娘越美，诗人的心越乱。它是中国诗歌里"月亮"和"美人"结伴登场的老祖先，后来李白写"床前明月光"、苏轼说"月下独酌"，都还受着这首小诗的影响呢！短短几句，没有一个"爱"字，却把相思写得清清楚楚。` }] },
  { id: 25, title: "汉广（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "南有乔木，不可休思，汉有游女，不可求思，汉之广矣，不可泳思",
    tags: "诗经,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "汉广（节选）", original: `南有乔木，不可休思。
汉有游女，不可求思。
汉之广矣，不可泳思。
江之永矣，不可方思。`, translation: `南方有棵高大的树，却不能到它下面去休息。汉水边有个游玩的姑娘，却不能去追求她。汉水呀，又宽又广，想游过去也不行。长江呀，又长又远，想绕过去也不成。`, interpretation: `这是三千年前一位年轻的樵夫唱的歌。那时候，江汉一带是楚国的地方，树木茂盛，汉水边常有出游的女子。小伙子远远看见一位美丽的姑娘，心里喜欢得不行，可就是够不着——树太高歇不了凉，水太宽游不过去，江太长绕不过去。他用“高高的树”“宽宽的江”来形容自己追不到心爱姑娘的愁苦，全诗翻来覆去念着“不可”“不可”，像在叹气。这种“求之不得”的心情，从古唱到今，后来人常说“可望而不可即”，就是这种滋味儿呢！` }] },
  { id: 26, title: "柏舟（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "泛彼柏舟，亦泛其流，耿耿不寐，如有隐忧，我心匪石，不可转也",
    tags: "诗经,感怀",
    color: "#d97706",
    sections:[    { id: 1, title: "柏舟（节选）", original: `泛彼柏舟，亦泛其流。
耿耿不寐，如有隐忧。
我心匪石，不可转也。
我心匪席，不可卷也。`, translation: `那艘柏木小船在水里漂啊漂，顺着河水一起向前流。我躺在床上翻来覆去睡不着，心里好像藏着说不出的忧愁。我的心可不是石头，不能随便让人翻转；我的心也不是席子，不能随便让人卷起来。`, interpretation: `这首诗来自两千多年前的《诗经》，是一位女子在深夜写下的心声。那时候女子地位低微，常常受委屈却无处诉说。诗里的“柏舟”是用柏树木做的小船，象征着女子柔弱却坚定的品格。她反复说自己的心“不是石头，不是席子”，意思是自己有主见、有骨气，绝不会因为别人说什么就改变想法。这种倔强的语气，在那个年代特别勇敢，也特别让人心疼。后来“我心匪石，不可转也”成了千古名句，常被用来形容人要有坚定的信念和立场。整首诗语言质朴，情感却非常强烈，是中国最早的“女性宣言”呢！` }] },
  { id: 27, title: "伐檀（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "坎坎伐檀兮，置之河之干兮，不稼不穑胡取禾三百廛兮",
    tags: "诗经,讽刺",
    color: "#d97706",
    sections:[    { id: 1, title: "伐檀（节选）", original: `坎坎伐檀兮，置之河之干兮。
河水清且涟猗。
不稼不穑，胡取禾三百廛兮？
不狩不猎，胡瞻尔庭有县貆兮？
彼君子兮，不素餐兮！`, translation: `叮叮当当砍檀树啊，把树干放在河岸边啊。河水清清泛着波纹啊。
不种田不收割，为什么拿走三百家的稻谷啊？不打猎不捕兽，为什么你家院子里挂满獾啊？
那些贵族老爷们啊，可不是白白吃闲饭的啊！`, interpretation: `这首诗出自《诗经·魏风》，大约写于2500多年前的春秋时期。那时候贵族压迫百姓，劳动者辛苦一年却吃不饱饭。
诗中有个特别聪明的写法——一边干活一边发牢骚：砍着檀树，看着清清的河水，再回头看看自己辛苦劳作却穷得叮当响，而那些不干活的人家里却挂满了猎物，堆满了粮食。这种对比多么强烈！
最后一句“彼君子兮，不素餐兮”是反话，意思是：那些所谓的'君子'啊，难道是白吃饭的吗？表面上像是尊敬，其实是在狠狠嘲笑。
这种“一面干活一面吐槽”的写法，后来成了中国古典诗歌的经典传统，屈原、杜甫、白居易都学过这一招呢！` }] },
  { id: 28, title: "硕鼠",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "硕鼠硕鼠，无食我黍，三岁贯女，莫我肯顾，逝将去女，适彼乐土",
    tags: "诗经,讽刺",
    color: "#d97706",
    sections:[    { id: 1, title: "硕鼠", original: `硕鼠硕鼠，无食我黍！
三岁贯女，莫我肯顾。
逝将去女，适彼乐土。
乐土乐土，爰得我所！`, translation: `大田鼠啊大田鼠，别再吃我种的黄米啦！多年辛苦养活你，你却一点也不肯照顾我。我发誓一定要离开你，去那美好的地方。乐土啊乐土，那才是我该去的好去处！`, interpretation: `这首诗出自2500多年前的《诗经》，那时候农民辛苦种粮食，却被贵族统治者层层剥削，心里又气又无奈。诗人把剥削者比作又肥又大的田鼠——偷吃粮食，胖嘟嘟的，却一点不顾主人的死活。'三岁贯女，莫我肯顾'特别有名，意思是养了你多年，你却翻脸不认人！全诗反复念着'乐土乐土'，就像孩子盼着有一天能逃到没有坏人的地方。读起来押韵上口，还带着一股不服气的小脾气，是中国最早的'逃跑歌'之一，后来'逝将去女'成了古人表达决绝的经典名句。` }] },
  { id: 29, title: "鹿鸣（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "呦呦鹿鸣，食野之苹，我有嘉宾，鼓瑟吹笙",
    tags: "诗经,宴饮",
    color: "#d97706",
    sections:[    { id: 1, title: "鹿鸣（节选）", original: `呦呦鹿鸣，食野之苹。
我有嘉宾，鼓瑟吹笙。`, translation: `野地里，鹿儿轻轻叫，它们正啃着青草。我有尊贵的朋友来做客，我高兴地弹起瑟，吹起笙。`, interpretation: `这首诗出自两千多年前，是周王宴请宾客时唱的歌曲。古人爱在打猎时模仿鹿叫，没想到一群鹿正在原野上悠闲地吃着野草，这个画面被诗人写进了诗里。最妙的就是"呦呦鹿鸣"这四个字，成了流传千古的名句。后来曹操的"呦呦鹿鸣，食野之蒿"，就是从这里学来的。弹琴吹笙迎接客人，可见古人多么热情好客！` }] },
  { id: 30, title: "相鼠",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "相鼠有皮，人而无仪，人而无仪，不死何为",
    tags: "诗经,讽刺",
    color: "#d97706",
    sections:[    { id: 1, title: "相鼠", original: `相鼠有皮，人而无仪。
人而无仪，不死何为！
相鼠有齿，人而无止。
人而无止，不死何俟！`, translation: `你瞧那老鼠还有张皮呢，人要是不要脸面，那还活着干什么呀？你瞧那老鼠还有牙齿呢，人要是没有品德，那还等什么呢（不如早点死掉）？`, interpretation: `这首诗来自大约两千多年前的《诗经》，那时候贵族们常常举办典礼和宴会，有些当官的虽然穿着漂亮衣服，却做事没规矩、品德很糟糕。这首小诗就是专门骂那些虚伪之人的——你看，连老鼠都有皮有齿，你堂堂一个人，连最起码的礼仪廉耻都不要了吗？它最大的特色就是用最简单的话说出最重的责骂，三句一重复，像在指着鼻子质问对方。这种'直接开骂'的写法在《诗经》里特别少见，读起来痛快又解气，也让我们看到古人并不是只会客气，他们也会用犀利的诗表达愤怒。` }] },
  { id: 31, title: "七月（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "七月流火，九月授衣，春日载阳，有鸣仓庚",
    tags: "诗经,农事",
    color: "#d97706",
    sections:[    { id: 1, title: "七月（节选）", original: `七月流火，九月授衣。
春日载阳，有鸣仓庚。
女执懿筐，遵彼微行，爰求柔桑。
七月在野，八月在宇，九月在户，十月蟋蟀入我床下。`, translation: `七月大火星向西偏，天气转凉啦；九月就把冬衣来发放。春天太阳暖洋洋，黄莺儿叫得真响亮。姑娘们提着深竹筐，顺着小路走，去采那嫩嫩的桑叶。七月蟋蟀还在田野里，八月跳到屋檐下，九月躲到门里面，十月钻到我床底下啦。`, interpretation: `这首诗来自两千多年前的西周，是农民伯伯一边干活一边唱的歌。那时候没有日历表，人们抬头看天上的大火星来定季节。大火星一偏西，夏天就过去啦，该准备过冬的衣服了。诗里最有意思的是写蟋蟀搬家：七月在野地，八月到屋檐，九月进房门，十月钻床底——跟着天气变冷一步步往屋里跑，多可爱呀！这种把虫子当主角来写的法子特别生动，后来李白、杜甫都爱学这种'顺着季节讲故事'的写法呢。` }] },
  { id: 32, title: "绿衣",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "绿兮，衣兮",
    tags: "诗经,悼亡",
    color: "#d97706",
    sections:[    { id: 1, title: "绿衣", original: `绿兮衣兮，绿衣黄裹。
心之忧矣，曷维其已！
绿兮衣兮，绿衣黄裳。
心之忧矣，曷维其亡！
绿兮丝兮，女所治兮。
我思古人，俾无訧兮！
絺兮绤兮，凄其以风。
我思古人，实获我心！`, translation: `绿色的外衣啊，绿上衣配黄色衬里。看到它，我心里好难过，这悲伤什么时候才能停止啊！绿色的外衣啊，绿上衣配黄色下裙。看到它，我心里好难过，这思念什么时候才能忘怀啊！那绿色的丝线啊，全是你亲手纺出来的。我想起去世的妻子啊，她让我从没有过错！细麻布啊粗麻布啊，天冷了穿在身上多么凉啊。我想起去世的妻子啊，她最懂我的心思！`, interpretation: `这首诗出自《诗经·邶风》，大约是公元前500多年前的作品。相传是卫庄姜或一位贵族男子为悼念亡妻而作，充满了对已故爱人的深切思念。诗人触物伤情，看到妻子亲手缝制的绿色衣裳和丝线，便悲从中来——'绿衣黄裳'是衣物的颜色，'黄裹'是黄色的衬里，这些细致的描写说明他一直珍藏着亡妻的遗物。最动人的是'我思古人，实获我心'——世上再没有人像她那样懂我。这首诗开创了中国诗歌'悼亡'题材的先河，后世潘岳的《悼亡诗》、元稹的'曾经沧海难为水'、苏轼的'十年生死两茫茫'，都受到了这首小诗的影响。可以说，悼念亲人的深情，从三千年前就开始打动人心了。` }] },
  { id: 33, title: "哀郢（节选）",
    author: "屈原",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "鸟飞反故乡兮狐死必首丘",
    tags: "楚辞,感怀",
    color: "#d97706",
    sections:[    { id: 1, title: "哀郢（节选）", original: `鸟飞反故乡兮，狐死必首丘。
信非吾罪而弃逐兮，何日夜而忘之！`, translation: `鸟儿飞得再远也要回到自己的巢穴，狐狸临死时也必定把头朝向出生的小山。我真的没有犯什么罪啊，却被放逐流落他乡！`, interpretation: `这首诗写于战国末期，秦国大军攻占了楚国都城郢都，屈原被迫流亡，眼看家园沦丧，悲痛万分。诗中用鸟归巢、狐首丘两个动人故事，说明万物都眷恋故土，反衬出自己被迫离乡的哀伤。屈原通过奇特的想象和真挚的情感，让读者仿佛看见一位白发老人在江边独自垂泪。这种深沉的家国情怀，后来成为中国人心中爱国忧民的精神象征。` }] },
  { id: 34, title: "九辩（节选）",
    author: "宋玉",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "悲哉秋之为气也萧瑟兮草木摇落而变衰",
    tags: "楚辞,感怀",
    color: "#d97706",
    sections:[    { id: 1, title: "九辩（节选）", original: `悲哉秋之为气也！萧瑟兮，草木摇落而变衰。
憭栗兮，贫士失职而志不平。
廓落兮，羁旅而无友生。`, translation: `秋天真让人伤心啊，一片凄凉冷清！草木在秋风中摇摆凋零，变得枯萎衰败。可怜那些贫寒的读书人失去了官职，心里满是委屈和不平，觉得世界空旷又孤独。`, interpretation: `这是战国时期楚国诗人宋玉写的《九辩》中的句子，开创了中国文学“悲秋”的传统。在那战乱纷争、仕途坎坷的年代，读书人常常怀才不遇，宋玉借秋天的萧瑟抒发自己内心的苦闷。诗中最妙的就是把“秋天”和“失意的读书人”连在一起——草木衰落就像人才被埋没，从此“悲秋”成了文人表达失意、孤独的经典方式，影响了杜甫、柳永等无数后辈诗人。` }] },
  { id: 35, title: "山鬼（节选）",
    author: "屈原",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "若有人兮，山之阿被薜荔兮，带女萝既含睇兮",
    tags: "楚辞,神话",
    color: "#d97706",
    sections:[    { id: 1, title: "山鬼（节选）", original: `若有人兮，山之阿。
被薜荔兮，带女萝。
既含睇兮，又宜笑。
乘赤豹兮，从文狸。
辛夷车兮，结桂旗。
风飒飒兮，木萧萧。
思公子兮，徒离忧。`, translation: `好像有个人儿啊，住在山坳里，身披薜荔香草，腰系女萝长带。眼波流转含情脉脉，笑容温柔又美好。骑着红色的豹子，后面跟着花纹的野狸。辛夷做的花车，桂花枝扎成的彩旗。风吹过来，树叶沙沙响，她啊，心里想念着那位公子。`, interpretation: `这首《山鬼》出自战国时期楚国大诗人屈原的《九歌》，写的是一位住在深山里的女神——山鬼姑娘。屈原被流放后，吸收楚地民间祭歌的养分，写下了这些美丽的诗篇。诗中最有画面感的是山鬼的出行：赤豹拉车、文狸跟随、辛夷为车、桂枝为旗，想象多么奇特！山风吹过树梢沙沙作响，她却在痴痴等待心上人。这份等待中的孤独与深情，让两千多年后的我们读来仍然心动。它告诉我们：古人不只有严肃的道理，屈原笔下的神话世界也可以这样浪漫而温柔。` }] },
  { id: 36, title: "江南",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "江南可采莲，莲叶何田田，鱼戏莲叶间",
    tags: "汉,经典",
    color: "#dc2626",
    sections:[    { id: 1, title: "江南", original: `江南可采莲。
莲叶何田田！
鱼戏莲叶间。
鱼戏莲叶东，鱼戏莲叶西，
鱼戏莲叶南，鱼戏莲叶北。`, translation: `江南真是个好地方，可以去采莲啦！莲叶长得多么茂密又鲜艳！鱼儿在水里嬉戏，一会儿游到莲叶的东边，一会儿游到莲叶的西边，一会儿游到莲叶的南边，一会儿又游到莲叶的北边，到处欢快地玩耍。`, interpretation: `这是一首汉代流传下来的采莲歌，歌词本该是“江南可采莲，莲叶何田田”，后面原是“鱼戏莲叶间”加上“东西南北”四个方向。但因为古人写书没有标点，抄来抄去就挤成了一团，变成了我们今天看到的样子。诗里描绘了江南水乡少女一边采莲、一边看鱼儿在莲叶间穿梭的欢乐情景，画面清新活泼。鱼儿在东南西北四处游动，仿佛在和采莲人捉迷藏，特别有趣味。这首汉乐府小诗语言明快、节奏感强，后人常把它当作儿歌来读，千年传唱不衰。` }] },
  { id: 37, title: "长歌行",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "少壮不努力，老大徒伤悲",
    tags: "汉,哲理",
    color: "#dc2626",
    sections:[    { id: 1, title: "长歌行", original: `青青园中葵，朝露待日晞。
阳春布德泽，万物生光辉。
常恐秋节至，焜黄华叶衰。
百川东到海，何时复西归？
少壮不努力，老大徒伤悲！`, translation: `绿油油的菜园里长着向日葵
清晨的露珠等着太阳来晒干
春天把阳光雨露洒向人间
世上的万物都焕发着光彩
常常担心秋天匆匆到来
叶子变黄、花儿凋零一片衰败
无数江河向东奔流入大海
什么时候才能再向西流回
人在年轻力壮时不发奋努力
到了年老体衰时只能空悲伤`, interpretation: `这首汉代乐府诗像一位慈祥的长辈在和你聊天。它先用葵菜沾露、春天生辉的美好画面让你沉浸其中，再突然话锋一转：秋天一来，叶子枯黄；江河东去，永不西归——时间就是这样一去不回头呀！最后两句是全诗最响亮的警钟，告诉我们：小时候不努力，长大只能后悔。这首诗最厉害的地方是用我们身边看得见、摸得着的事物来讲大道理，所以一千多年来，每当有人虚度光阴，大人们就会念起'少壮不努力，老大徒伤悲'这两句话。它还被写进无数学校的墙上，成了陪伴一代代孩子长大的'座右铭'呢！` }] },
  { id: 38, title: "观沧海",
    author: "曹操",
    dynasty: "三国",
    category: "三国",
    summary: "东临碣石，以观沧海，日月之行，若出其中，星汉灿烂，若出其里",
    tags: "汉,写景",
    color: "#dc2626",
    sections:[    { id: 1, title: "观沧海", original: `东临碣石，以观沧海。
水何澹澹，山岛竦峙。
树木丛生，百草丰茂。
秋风萧瑟，洪波涌起。
日月之行，若出其中；
星汉灿烂，若出其里。
幸甚至哉，歌以咏志。`, translation: `我向东爬上了碣石山，来欣赏大海的壮丽景色。海水波涛起伏，多么宽广。远处的小山和岛屿高高地矗立着。岛上树木茂盛，各种各样的草长得又密又旺。秋风吹来，发出沙沙的声音，巨大的海浪翻涌起来。太阳和月亮的运行，好像都是从这片大海里升起来的。灿烂的银河，也好像是从大海里流出来的。`, interpretation: `这首诗写于公元207年，曹操北征乌桓凯旋途中。登上碣石山，他被眼前的大海深深震撼，于是写下了这首气吞山河的诗。诗中“澹澹”的海水、“竦峙”的山岛、“丰茂”的百草，都是大自然的实景，但最妙的是最后四句——太阳、月亮、银河，都好像是从大海里升起，曹操用这种夸张的想象，把大海写得比天还大。这正是他胸中统一天下抱负的写照：一个能包容宇宙的人，才能成就大事业。这种以景抒怀的写法，后来被很多诗人学习，比如毛泽东的《浪淘沙·北戴河》就化用了“秋风萧瑟，洪波涌起”。` }] },
  { id: 39, title: "龟虽寿",
    author: "曹操",
    dynasty: "三国",
    category: "三国",
    summary: "老骥伏枥，志在千里，烈士暮年，壮心不已",
    tags: "汉,哲理",
    color: "#dc2626",
    sections:[    { id: 1, title: "龟虽寿", original: `神龟虽寿，犹有竟时。
腾蛇乘雾，终为土灰。
老骥伏枥，志在千里；
烈士暮年，壮心不已。
盈缩之期，不但在天；
养怡之福，可得永年。
幸甚至哉，歌以咏志。`, translation: `传说中的神龟虽然特别长寿，但终究也有死亡的一天。能够腾云驾雾的飞蛇，最终也会变成土和灰。千里马老了趴在马槽里，可它的志向仍然是驰骋千里。有抱负的人到了晚年，雄心壮志也丝毫不会减退。寿命的长短，不完全由老天爷决定。只要保养得好心情愉快，也能健康长寿活到一百岁。`, interpretation: `这是曹操五十三岁时写下的名篇《龟虽寿》。东汉末年天下大乱，他率军北征乌桓凯旋，豪情满怀之际写下这组诗，鼓励自己也要鼓励将士们不要服老。诗中最闪亮的意象就是"老骥伏枥，志在千里"——千里马老了趴在槽头，心里想的还是奔跑万里，多么有气势！这句诗也成为千古名句，激励着无数人不论年纪多大，都要保持一颗向前的心。这首诗最厉害的地方在于：前四句说神龟飞蛇都有尽头，似乎很悲观；后四句笔锋一转，说人的寿命靠自己来掌握，充满了昂扬向上的力量，让短短几十个字里既有哲理又有热血，特别适合少年人诵读记诵。` }] },
  { id: 40, title: "短歌行（节选）",
    author: "曹操",
    dynasty: "三国",
    category: "三国",
    summary: "对酒当歌，人生几何，青青子衿，悠悠我心，周公吐哺，天下归心",
    tags: "汉,抒情",
    color: "#dc2626",
    sections:[    { id: 1, title: "短歌行（节选）", original: `对酒当歌，人生几何？
譬如朝露，去日苦多。
慨当以慷，忧思难忘。
何以解忧？唯有杜康。
青青子衿，悠悠我心。
但为君故，沉吟至今。
呦呦鹿鸣，食野之苹。
我有嘉宾，鼓瑟吹笙。
明明如月，何时可掇？
忧从中来，不可断绝。
越陌度阡，枉用相存。
契阔谈䜩，心念旧恩。
月明星稀，乌鹊南飞。
绕树三匝，何枝可依？
山不厌高，海不厌深。
周公吐哺，天下归心。`, translation: `对着美酒就该放声高歌，人生能有多少好时光？就像早晨的露水，太阳一晒就没了，逝去的日子苦多乐少啊。心中激荡满腔不平，可愁绪却总也难忘。什么东西能消除烦恼？只有美酒杜康。穿青衣的读书人啊，我日夜把你们挂念。只因为你们的缘故，我低声吟唱直到今天。月色明亮，星星稀少，乌鸦和喜鹊向南飞去。山的胸怀不嫌高，海的度量不嫌深。周公热情接待贤才，天下人都甘心归顺。`, interpretation: `这首诗写于东汉末年，天下大乱，曹操雄心勃勃想要统一中国，却苦于身边人才不足。一边喝酒一边唱歌，表面上感叹人生短暂像朝露易干，其实是在抒发求贤若渴的焦急心情。他用“青青子衿”直接喊话读书人快来投奔我，又用“山不厌高，海不厌深”打比方——山再高也不嫌堆得更高，海再深也不嫌灌得更深，表示自己容人的气量有多大。最后搬出周公“一顿饭吃三次、吐出来接待贤人”的典故，意思是说：你们来了，我一定好好对待。短短几句，把一个政治家的豪情和心事写得明明白白，后来“对酒当歌”成了形容豪迈气概的常用语，流传了一千八百年。` }] },
  { id: 41, title: "蒿里行",
    author: "曹操",
    dynasty: "三国",
    category: "三国",
    summary: "白骨露于野，千里无鸡鸣，生民百遗一，念之断人肠",
    tags: "汉,战争",
    color: "#dc2626",
    sections:[    { id: 1, title: "蒿里行", original: `关东有义士，兴兵讨群凶。
初期会盟津，乃心在咸阳。
军合力不齐，势利使人争。
淮南弟称号，刻玺于北方。
铠甲生虮虱，万姓以死亡。
白骨露于野，千里无鸡鸣。
生民百遗一，念之断人肠。`, translation: `函谷关以东有各路起义军，他们起兵讨伐那些凶恶的乱臣贼子。可是各路军队聚集在一起，却不能齐心协力，因为权势和利益让人们互相争斗。将士们长期征战，身上的铠甲里都长出了虱子的幼虫（虮），老百姓大量死亡，尸骨遍野，千里之地听不到一声鸡叫。活下来的人一百个里只剩下一两个。想到这些惨状，真让人肝肠寸断。`, interpretation: `这首诗写于东汉末年，那是群雄并起、战乱不断的年代。曹操作为一位有抱负的政治家和诗人，眼睁睁看着各路兵马各怀私心、不肯协力，导致战火连天、生灵涂炭。诗中最震撼的意象就是'白骨露于野，千里无鸡鸣'——遍地白骨、千里荒寂，连鸡叫的声音都没有，画面感极强，让人读来心惊。'生民百遗一'更是以数字写尽人间惨剧。这种直面现实的写法，让这首诗被誉为'汉末实录'，也开创了后世杜甫'诗史'传统的先河。` }] },
  { id: 42, title: "白马篇（节选）",
    author: "曹植",
    dynasty: "三国",
    category: "三国",
    summary: "捐躯赴国难，视死忽如归",
    tags: "三国,经典",
    color: "#f97316",
    sections:[    { id: 1, title: "白马篇（节选）", original: `白马饰金羁，连翩西北驰。
弃身锋刃端，性命安可怀？
父母且不顾，何言子与妻？
捐躯赴国难，视死忽如归。`, translation: `骑着白马拉金笼头，飞奔着向西北方向去。我既然投身在刀锋之间，哪里还顾得上自己的性命？连父母都顾不上了，更别提我的儿子和妻子。为国家献身去解救危难，把死亡看得像回家一样平常。`, interpretation: `这首诗写于三国时期，那时候群雄争霸，战争不断，年轻人纷纷投军报国。曹植用“白马”“金羁”勾勒出一位英俊少年英雄的形象，他骑着白马奔驰西北边塞，豪气冲天。诗中最动人的是“捐躯赴国难，视死忽如归”——为了国家，连死亡都像回家一样毫不在乎。这两句成为千古名句，激励了一代又一代的爱国志士。整首诗语言铿锵有力，对仗工整，读起来就像听到战鼓在响，特别有男子汉的豪情！` }] },
  { id: 43, title: "陌上桑（节选）",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "日出东南隅，照我秦氏楼，秦氏有好女，自名为罗敷",
    tags: "汉,叙事",
    color: "#dc2626",
    sections:[    { id: 1, title: "陌上桑（节选）", original: `日出东南隅，照我秦氏楼。
秦氏有好女，自名为罗敷。
行者见罗敷，下担捋髭须。
少年见罗敷，脱帽著帩头。
耕者忘其犁，锄者忘其锄。`, translation: `太阳从东南方升起来，阳光照在秦家的楼上。秦家有个美丽的姑娘，她的名字叫罗敷。过路的人看见了罗敷，放下担子捋着胡须。年轻人看见了罗敷，摘下帽子重新整理包头。耕地的人看见她，忘记了自己在犁地。锄地的人看见她，忘记了自己在锄地。`, interpretation: `这首《陌上桑》来自汉代，是一首讲故事的民歌。故事发生在日出东南的清晨，阳光照在秦家楼上，美丽的罗敷登场啦！作者没有直接写罗敷长得多漂亮，而是用了一个超厉害的写法——通过“行者”“少年”“耕者”“锄者”四种人的反应，从侧面烘托出罗敷的惊人美貌。这就是中国古诗里常说的“侧面描写”，比直接说“她真美”高明多啦！这首汉乐府后来还被改编成戏曲《秦香莲》的一部分，著名的诗句“行者见罗敷，下担捋髭须”传诵千年，成为了描写美人的经典名句。` }] },
  { id: 44, title: "十五从军征",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "十五从军征，八十始得归，羹饭一时熟，不知饴阿谁",
    tags: "汉,叙事",
    color: "#dc2626",
    sections:[    { id: 1, title: "十五从军征", original: `十五从军征，八十始得归。
道逢乡里人，家中有阿谁？
遥看是君家，松柏冢累累。
兔从狗窦入，雉从梁上飞。
中庭生旅谷，井上生旅葵。
烹谷持作饭，采葵持作羹。
羹饭一时熟，不知饴阿谁。
出门东向看，泪落沾我衣。`, translation: `十五岁就去当兵打仗，八十岁才终于回到家乡。路上遇到一个老乡，问：我家里还有什么人？老乡指着远处说：那是你的家，但已经是松树柏树掩映的坟墓了。一堆堆的坟头。野兔从狗洞钻进屋里，野鸡从房梁上扑棱飞起。院子里长着野生的谷子，井台边长着野生的葵菜。舀来煮成饭，一会儿就熟了，却不知道该给谁吃。走出门向东望去，泪水一串串落下，打湿了我的衣裳。`, interpretation: `这首汉代乐府诗写了一位少年从军、老来归家的老兵。背景是汉朝常年战乱，百姓被大量征召入伍，很多人一辈子都回不了家。诗中最震撼的意象是'松柏冢累累'——曾经的家变成了坟地，野兔从狗洞出入、野鸡在梁上飞，这些反常的细节让人感受到战乱年代的荒凉。诗最后'泪落沾我衣'，没有大哭大喊，只是一个老人默默流泪的样子，反而更让人心酸。这首诗用最简单的语言写出了最深的不幸，是古代战争诗中难得的写实杰作，后来杜甫的'无家问消息'等名句，都受到它的影响。` }] },
  { id: 45, title: "迢迢牵牛星",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "迢迢牵牛星，皎皎河汉女，盈盈一水间，脉脉不得语",
    tags: "汉,爱情",
    color: "#dc2626",
    sections:[    { id: 1, title: "迢迢牵牛星", original: `迢迢牵牛星，皎皎河汉女。
纤纤擢素手，札札弄机杼。
终日不成章，泣涕零如雨。
河汉清且浅，相去复几许？
盈盈一水间，脉脉不得语。`, translation: `那遥远又明亮的牵牛星啊，那皎洁美丽的织女。她伸出细长柔美的手，正在机杼上不停地织布。可是一整天也没织成一匹，眼泪像下雨一样落下来。那银河又清又浅，他们相隔能有多远呢？只隔着一条清澈的河流，却只能远远相望，谁也说不出话来。`, interpretation: `这首诗选自《古诗十九首》，大约诞生于东汉末年。那时候战乱频繁，人们常常离别，诗人借天上牛郎织女的故事，写出了人世间有情人不能相见的悲伤。诗里最动人的是"盈盈一水间，脉脉不得语"——明明只隔着一条清浅的河，却谁也不能开口说话，那种又近又远的感觉，是不是很像你和好朋友被分在不同班级时的想念？全诗十个叠字"迢迢、皎皎、纤纤、札札、盈盈、脉脉"连用，读起来像唱歌一样，是它最大的特色。后来"盈盈一水间，脉脉不得语"成了千古名句，连曹植、李白都学过这种写法呢！` }] },
  { id: 46, title: "行行重行行",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "行行重行行，与君生别离，相去万余里，各在天一涯",
    tags: "汉,情感",
    color: "#dc2626",
    sections:[    { id: 1, title: "行行重行行", original: `行行重行行，与君生别离。
相去万余里，各在天一涯。
道路阻且长，会面安可知？
胡马依北风，越鸟巢南枝。
相去日已远，衣带日已缓。
浮云蔽白日，游子不顾反。
思君令人老，岁月忽已晚。
弃捐勿复道，努力加餐饭。`, translation: `走啊走啊不停地走，就这样和你活生生地分开。我们相隔万里远，各自在一个天涯。路又险又长，什么时候才能再见面？北方的马总依恋着北风，南方的鸟把窝筑在南边的树枝上。分开的日子越来越远，我的衣带一天比一天宽松。想念你让人渐渐老去，一年又一年匆匆过去，岁月已晚。不要再说被抛弃的话了，你只管好好吃饭保重身体。`, interpretation: `这首诗出自汉代《古诗十九首》，是思乡念友诗中的名篇。当时许多读书人为了做官离开家乡，常年在外漂泊，特别思念亲人朋友。诗中用北马南鸟的有趣比喻，说明万物都眷恋故土，何况人呢？最后那句"努力加餐饭"流传千古，明明是自己吃不下饭，却叮嘱对方保重，说不出的牵挂都藏在饭菜里。这首诗最大的特点就是不说大道理，全用家常话诉说真情，所以特别打动人心。` }] },
  { id: 47, title: "涉江采芙蓉",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "涉江采芙蓉，兰泽多芳草，采之欲遗谁，所思在远道",
    tags: "汉,情感",
    color: "#dc2626",
    sections:[    { id: 1, title: "涉江采芙蓉", original: `涉江采芙蓉，长洲郁幽兰。
采之欲遗谁？所思在远道。
还顾望旧乡，长路漫浩浩。
同心而离居，忧伤以终老。`, translation: `我渡过江水去采摘荷花，兰花生长的地方长满了香草。我采了这些花想送给谁呢？我想念的人啊，在很远很远的地方。回头望一望家乡，漫漫长路无边无尽。我们明明是相爱的人，却要分开两地，只能带着这份忧伤，慢慢变老。`, interpretation: `这首诗出自《古诗十九首》，是东汉末年的作品。那时候社会动荡，很多人离开家乡去远方谋生，和亲人、爱人长久分离。诗里写一个人渡过江水去采荷花，想送给远方的心上人，可怎么都够不到，只能回头望着家乡叹气。最动人的是最后两句——明明是相爱的人，却被距离隔开，一辈子都在思念中度过。这种'想见却见不到'的心情，几百年来打动了一代又一代人，成了思念远方亲人时最常被想起的诗句。` }] },
  { id: 48, title: "明月何皎皎",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "明月何皎皎，照我罗床帏，忧愁不能寐，揽衣起徘徊",
    tags: "汉,情感",
    color: "#dc2626",
    sections:[    { id: 1, title: "明月何皎皎", original: `明月何皎皎，照我罗床帏。
忧愁不能寐，揽衣起徘徊。
客行虽云乐，不如早旋归。
出户独彷徨，愁思当告谁？
引领还入房，泪下沾裳衣。`, translation: `明月多么明亮皎洁呀，清冷的光辉照进了我的罗帐床帏。我满心忧愁，怎么也睡不着，只好披上衣服起来在屋里走来走去。听说出门在外也许很快乐，可我总觉得，还不如早些回家乡。我走出门独自徘徊，满腹的愁苦又能讲给谁听？抬头望天久久出神，最终还是转身回到房里，伤心落下的泪水打湿了衣裳。`, interpretation: `这首诗出自汉代《古诗十九首》，是一位漂泊在外的游子在月夜写下的思念家乡之作。那时候很多人为了求学、做官或谋生，不得不背井离乡长年在外，想家是特别普遍的情感。诗中最打动人的意象就是那轮明月——它照进屋里，照出孤单，也照出游子无处安放的心。你看诗人多可爱，睡不着就起来溜达，出了门又不知该去哪儿，最后还是哭着回屋，把所有情绪都留给了月光。整首诗语言朴素，却写出了每个人都会有的"夜里想家"的体验，所以千百年来一直被人们传诵。` }] },
  { id: 49, title: "西北有高楼",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "西北有高楼，上与浮云齐，不惜歌者苦，但伤知音稀",
    tags: "汉,感怀",
    color: "#dc2626",
    sections:[    { id: 1, title: "西北有高楼", original: `西北有高楼，上与浮云齐。
交疏结绮窗，阿阁三重阶。
上有弦歌声，音响一何悲。
不惜歌者苦，但伤知音稀。
愿为双鸿鹄，奋翅起高飞。`, translation: `西边的天空中有一座高高的楼阁，它高高耸立，仿佛和天上飘浮的云朵一样高。楼上的窗户雕刻着精美的花纹，格子交错十分华丽。楼阁下面还有三层高高的台阶。楼上传来了弹琴唱歌的声音，这声音听起来多么悲伤啊！我并不是心疼唱歌人内心的苦楚，只是感慨这世上能听懂我心事的人实在太少了。真希望自己能变成一只展翅高飞的天鹅，和知音一起远走高飞。`, interpretation: `这首诗来自东汉，是《古诗十九首》中的一首，写于那个动荡不安的年代。许多读书人满腹才华却得不到赏识，心里非常苦闷。诗中有一座高高的楼阁，楼上传出悲伤的歌声，诗人路过听到，心里很有感触。"高楼""弦歌""鸿鹄"这几个意象特别美——高楼代表远大的理想，弦歌代表知音难觅，鸿鹄代表高远的志向。最打动人的是"不惜歌者苦，但伤知音稀"这两句，说出了千百年来人们的心声：真正懂你的人，比什么都珍贵。这种怀才不遇、渴望知己的情感，后来被无数诗人写过，比如俞伯牙摔琴谢知音的故事，就和这句诗的意思一模一样。` }] },
  { id: 50, title: "上邪",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "上邪我欲与君相，知长命无绝衰山，无陵江水为竭冬，雷震震夏雨雪天，地合乃敢与君绝",
    tags: "汉,爱情",
    color: "#dc2626",
    sections:[    { id: 1, title: "上邪", original: `上邪！
我欲与君相知，长命无绝衰。
山无陵，江水为竭，
冬雷震震，夏雨雪，
天地合，乃敢与君绝！`, translation: `天啊！我想和您相知相爱，除非生命终结，这份爱才可能断绝。除非高山变成平地，江水干涸见底，冬天雷声轰隆隆地响，夏日里大雪纷飞，除非天地合在一起，我才敢和您分开。`, interpretation: `这首诗来自汉代，是一位女子对爱情发出的惊天誓言。那时的女子不善于表达情感，但诗中的她却如此勇敢热烈。诗人连用五种不可能发生的自然现象——山崩、江枯、冬雷、夏雪、天地合一，来反衬自己对爱情的忠贞。写法上想象大胆、排山倒海，气势震撼。这几句誓言成为千古名句，至今读来仍让人心头滚烫。` }] },
  { id: 51, title: "大风歌",
    author: "刘邦",
    dynasty: "汉",
    category: "汉",
    summary: "大风起兮云飞扬，威加海内兮归故乡，安得猛士兮守四方",
    tags: "汉,经典",
    color: "#dc2626",
    sections:[    { id: 1, title: "大风歌", original: `大风起兮云飞扬。
威加海内兮归故乡。
安得猛士兮守四方！`, translation: `大风刮起来了呀，云在空中飞扬。我现在威名震天下，终于回到了故乡。怎样才能得到勇猛的将士，替我守护四方疆土呢？`, interpretation: `这是汉高祖刘邦平定天下后，回到故乡沛县时所作。公元前196年，他战胜项羽建立汉朝，衣锦还乡，召集旧日好友饮酒庆祝。诗中短短三句，却藏着三层心情：起首一句气势磅礴，大风与飞云象征天下动荡；第二句难掩得意，'威加海内'写出他统一四海的豪情；第三句笔锋一转，从喜悦落入忧思——打天下容易，守天下难啊，他渴望有勇士帮他镇守辽阔的疆土。这首诗最妙的地方在于'得意不忘忧'，一个开国皇帝既有英雄气概，又有深谋远虑。后人常引用'威加海内'来形容功成名就，而'安得猛士兮守四方'也成为求贤若渴的千古名句。` }] },
  { id: 52, title: "垓下歌",
    author: "项羽",
    dynasty: "汉",
    category: "汉",
    summary: "力拔山兮，气盖世时不利兮，骓不逝虞兮，虞兮",
    tags: "汉,经典",
    color: "#dc2626",
    sections:[    { id: 1, title: "垓下歌", original: `力拔山兮气盖世。
时不利兮骓不逝。
骓不逝兮可奈何？
虞兮虞兮奈若何！`, translation: `我的力气能拔起大山啊，豪气压倒世上所有人！可是时运对我不利啊，连我的乌骓马也跑不动了。乌骓马跑不动啊，我又能怎么办呢？虞姬啊虞姬，我又该拿你怎么办呢？`, interpretation: `这是两千多年前西楚霸王项羽在乌江边自刎前唱的歌。当时项羽被刘邦的军队团团围住，四面传来楚国的歌声，他知道自己已经走投无路了。这首诗短短几句，却让人看到一个英雄的无奈与柔情——既有拔山盖世的霸气，也有对爱马和爱人虞姬的深深牵挂。特别是'虞兮虞兮奈若何'这一句，千百年来读起来都让人心酸难过。项羽虽然最后失败了，但他这份真性情，反而让他成了中国人心中最让人同情的英雄之一。` }] },
  { id: 53, title: "白头吟",
    author: "卓文君",
    dynasty: "汉",
    category: "汉",
    summary: "皑如山上雪，皎若云间月，愿得一心人，白头不相离",
    tags: "汉,爱情",
    color: "#dc2626",
    sections:[    { id: 1, title: "白头吟", original: `皑如山上雪，皎若云间月。
闻君有两意，故来相决绝。
今日斗酒会，明旦沟水头。
躞蹀御沟上，沟水东西流。
凄凄复凄凄，嫁娶不须啼。
愿得一心人，白头不相离。
竹竿何袅袅，鱼尾何簁簁。
男儿重意气，何用钱刀为！`, translation: `爱情应该像山顶上的雪一样洁白，又像云层中间的月亮一样明亮。我听说你有了二心，所以我来和你一刀两断。我只愿找到一个对我全心全意的人，相伴到老，白头偕老，永不分离。`, interpretation: `这首诗出自汉代才女卓文君之手，背景是她与才子司马相如的爱情故事——相如飞黄腾达后竟想另娶新欢，文君得知后悲愤交加，写下此诗。诗中最动人的是「皑如山上雪，皎若云间月」，用雪和月来比喻爱情的纯净美好，特别有画面感。而「愿得一心人，白头不相离」更是千古名句，道出了所有人对真爱的向往。文君没有哭哭啼啼，而是选择潇洒转身，这份骨气令人钦佩，也让她成为古代女性追求平等爱情的象征。` }] },
  { id: 54, title: "东门行",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "出东门不顾归盎中无斗米储架上无悬衣",
    tags: "汉,叙事",
    color: "#dc2626",
    sections:[    { id: 1, title: "东门行", original: `出东门，不顾归。
来入门，怅欲悲。
盎中无斗米储，还视架上无悬衣。
拔剑东门去，舍中儿母牵衣啼。
他家但愿富贵来，贱妾与君共哺糜。`, translation: `走出东门头也不回，
回到家中心里愁闷好后悔。
想要悲伤的是：米缸里没有一斗米的存粮。
回头看看衣架上，也没有一件可以穿的衣服。
一狠心，拔剑冲出东门去。
家里的小娃娃抱住他的衣服哭着不让走。
孩子说：我只盼着咱们家能富贵起来，
就算贫贱，也愿意和爸爸你一起喝稀粥过日子呀！`, interpretation: `这首汉代乐府诗来自两千多年前，没有留下作者的名字。它讲的是一位走投无路的父亲，因为家里揭不开锅、衣架上没有衣裳，被迫出门去做强盗。可刚迈出家门，小儿子就扯着他的衣角哭喊：就算穷得喝稀粥，也愿和爸爸在一起！短短几句话，写尽了汉代底层百姓的辛酸。诗中最动人的就是孩子那句"贱妾与君共哺糜"——穷，却有真情。这首《东门行》被后世称为"汉乐府第一佳作"，因为它不加修饰，像生活本身一样真实有力。` }] },
  { id: 55, title: "桃花源记（节选）",
    author: "陶渊明",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "忽逢桃花林夹岸数百步中无杂树芳草鲜美落英缤纷",
    tags: "魏晋南北朝,经典",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "桃花源记（节选）", original: `晋太元中，武陵人捕鱼为业。
缘溪行，忘路之远近。
忽逢桃花林，夹岸数百步，中无杂树，芳草鲜美，落英缤纷。
土地平旷，屋舍俨然，有良田、美池、桑竹之属。
阡陌交通，鸡犬相闻。`, translation: `东晋太元年间，有个武陵人靠打鱼为生。他沿着溪水划船前行，忘记走了多远。忽然遇到一片桃花林，溪水两岸几百步都是桃树，中间没有别的树。芬芳的青草鲜嫩美丽，落下的花瓣纷纷扬扬。土地平坦开阔，房屋整整齐齐，还有肥沃的田地、美丽的池塘和桑树竹林这类景物。田间小路纵横交错，村子里能听见鸡叫狗叫的声音。`, interpretation: `东晋时期战乱频繁，百姓生活困苦，陶渊明就写下了这篇美丽的桃花源故事。这段话描述了渔人意外发现世外桃源的过程，"桃花林"是他心中理想世界的入口，落英缤纷的景象美得像一场梦。陶渊明用白描手法，不加修饰地铺陈出一幅安宁祥和的田园画面，让人读了心里也觉得平静舒服。"阡陌交通，鸡犬相闻"成了千古名句，后来很多人用"世外桃源"来形容那些远离烦恼的美好地方。` }] },
  { id: 56, title: "归园田居·其一",
    author: "陶渊明",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "少无适俗韵，性本爱丘山，误落尘网中，一去三十年，久在樊笼里，复得返自然",
    tags: "魏晋南北朝,田园",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "归园田居·其一", original: `少无适俗韵，性本爱丘山。
误落尘网中，一去三十年。
羁鸟恋旧林，池鱼思故渊。
开荒南野际，守拙归园田。
方宅十余亩，草屋八九间。
榆柳荫后檐，桃李罗堂前。
暧暧远人村，依依墟里烟。
狗吠深巷中，鸡鸣桑树颠。
久在樊笼里，复得返自然。`, translation: `我从小就没有适应世俗的性格，天生就热爱山川田园。谁知不小心掉进了那张烦人的官场大网里，一晃就困了整整十三年。我就像被关住的鸟想念老树林，池塘里的鱼思念原来的深潭。如今终于回到家乡，在南边的田野开荒种地，守护自己笨拙的本分，回到这可爱的田园。房子四周有十来亩地，茅屋有八九间。榆树和柳树遮住后屋檐，桃树和李树排列在堂屋前。远处的村庄隐隐约约，缕缕炊烟轻轻飘散。深巷里传来狗叫声，桑树顶上有公鸡在叫喊。我就像被关在笼子里太久，今天终于又能回到大自然身边。`, interpretation: `东晋末年，官场黑暗腐败，陶渊明做了十三年小官后终于辞职回家。这首诗就像他给自然写的一封情书，核心意象是'樊笼'和'自然'的对立——官场是牢笼，田园才是家。他用最朴素的句子写出了最美的乡村画面：榆柳桃李、鸡鸣狗吠、远村炊烟，几乎成了中国田园诗的标准画面。后人一提'田园'就会想到陶渊明，他也被称为'古今隐逸诗人之宗'，意思是写归隐生活，他可是老祖宗级别的！` }] },
  { id: 57, title: "饮酒·其五",
    author: "陶渊明",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "采菊东篱下，悠然见南山，此中有真意，欲辨已忘言",
    tags: "魏晋南北朝,田园",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "饮酒·其五", original: `结庐在人境，而无车马喧。
问君何能尔，心远地自偏。
采菊东篱下，悠然见南山。
山气日夕佳，飞鸟相与还。
此中有真意，欲辨已忘言。`, translation: `我家盖房子就在人群聚居的地方，可是却没有车马的喧闹声。你要问我怎么能做到这样？只因心境清远，觉得所住的地方自然就偏僻安静了。在东边的篱笆墙下采摘菊花，一抬头，悠然自得地望见了南山。傍晚山间的云雾缭绕，景色十分美好，飞鸟也成群结伴地飞回山去。这中间蕴含着人生的真谛，想要辩说清楚，却忘了该用怎样的言语来表达。`, interpretation: `东晋末年官场黑暗，陶渊明不愿为五斗米折腰，辞官归隐，这首诗就写于他隐居田园之后。诗中最经典的意象是"采菊东篱下，悠然见南山"——菊花象征高洁，南山代表自然的宁静，诗人随手摘菊，无意间抬头望见青山，悠然二字写尽了自在与洒脱。陶渊明是中国田园诗的鼻祖，这首诗以平淡的语言写出深远的意境，告诉小朋友们：真正的快乐不在热闹的远方，而在一颗安静下来的心里。` }] },
  { id: 58, title: "木兰诗",
    author: "佚名",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "万里赴戎，机关山度，若飞将军，百战死壮，士十年归，同行十二，年不知木，兰是女郎",
    tags: "魏晋南北朝,经典",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "木兰诗", original: `唧唧复唧唧，木兰当户织。
不闻机杼声，唯闻女叹息。
问女何所思，问女何所忆。
女亦无所思，女亦无所忆。
昨夜见军帖，可汗大点兵。
军书十二卷，卷卷有爷名。
阿爷无大儿，木兰无长兄。
愿为市鞍马，从此替爷征。
万里赴戎机，关山度若飞。
朔气传金柝，寒光照铁衣。
将军百战死，壮士十年归。
归来见天子，天子坐明堂。
策勋十二转，赏赐百千强。
可汗问所欲，木兰不用尚书郎。
愿驰千里足，送儿还故乡。
爷娘闻女来，出郭相扶将。
阿姊闻妹来，当户理红妆。
小弟闻姊来，磨刀霍霍向猪羊。
开我东阁门，坐我西阁床。
脱我战时袍，著我旧时裳。
当窗理云鬓，对镜帖花黄。
出门看火伴，火伴皆惊惶。
同行十二年，不知木兰是女郎。`, translation: `唧唧又唧唧，木兰对着门在织布。听不到织机的声音，只听见姑娘在叹息。一遍又一遍叹息的是谁家的姑娘？木兰姑娘。

听不见木兰织布的声音，只听见她一声声叹息。

她愿去集市买来骏马和马鞍，从此代替父亲去出征。

到各处关口山岭行军如飞，北方的寒气传来打更声，冰冷的月光照着铁甲战衣。

将军身经百战有的战死沙场，壮士们十年后才得胜归来。

回到家乡，打开我东厢房的门，坐上我西厢房的床，脱下我打仗时的战袍，换上我旧日的姑娘衣裳。

战友同行十二年，竟不知木兰原是位女郎！`, interpretation: `《木兰诗》是北朝民歌，大约流传于一千五百年前。诗里讲了一个叫花木兰的女孩，女扮男装，替年迈的父亲从军打仗，立下功劳后回乡，才发现她其实是女儿身。

全诗最有趣的是两个"对比"：一是战场上英勇杀敌的"将军"，和回家后梳妆打扮的"姑娘"是同一个人；二是十二年的战友朝夕相处，居然"不知木兰是女郎"，让人忍不住笑出声来。

诗歌语言明快活泼，读起来像唱歌一样顺口。"万里赴戎机，关山度若飞"写出行军迅速，豪气十足；"开我东阁门，坐我西阁床"又回到家中，语气轻快。

木兰的故事传到今天，谁都知道"巾帼不让须眉"。她勇敢、孝顺、又机灵，是中国孩子最喜爱的古代女英雄之一呢！` }] },
  { id: 59, title: "拟行路难·其六（节选）",
    author: "鲍照",
    dynasty: "南北朝",
    category: "南北朝",
    summary: "对案不能食拔剑击柱长叹息自古圣贤尽贫贱何况我辈孤且直",
    tags: "魏晋南北朝,感怀",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "拟行路难·其六（节选）", original: `对案不能食，拔剑击柱长叹息。
丈夫生世会几时，安能蹀躞垂羽翼。
自古圣贤尽贫贱，何况我辈孤且直。`, translation: `对着饭菜却吃不下去，
拔出宝剑砍着柱子，满心愁苦。
叹息啊，大丈夫活在这世上，
什么时候才能有太平的时候？
就算像鸟儿一样垂下翅膀、迈着小步走，
自从古时候的圣贤以来，
都免不了贫穷和低贱，
何况我们这些又孤单又正直的人呢！`, interpretation: `这首诗写于南北朝那个乱糟糟的年代，鲍照家里穷，人又耿直，在官场里总被人排挤，心里憋了一肚子委屈。诗里最有意思的动作是“拔剑击柱”——想想看，一个书生气得拔剑去砍家里的柱子，那画面又急又无奈，真是太有感染力了！“蹀躞垂羽”说的是鸟儿收起翅膀、小心走路的样子，连圣贤都躲不过穷的命运，何况他这样性格直的人呢？这种“我穷我直我骄傲”的气魄，后来成了很多正直文人的心声，读起来特别痛快！` }] },
  { id: 60, title: "晚登三山还望京邑（节选）",
    author: "谢朓",
    dynasty: "南北朝",
    category: "南北朝",
    summary: "余霞散成绮，澄江静如练",
    tags: "魏晋南北朝,写景",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "晚登三山还望京邑（节选）", original: `灞涘望长安，河阳视京县。
白日丽飞甍，参差皆可见。
余霞散成绮，澄江静如练。
喧鸟覆春洲，杂英满芳甸。`, translation: `我就像当年在灞水边遥望长安的王粲，又像在河阳远眺京城的潘岳。京城的屋檐在阳光下闪着光，高高低低的房屋都能看得清楚。天边的晚霞散开，像一匹匹彩绸；清澈的江水静静地流淌，像一条白绢。喧闹的鸟儿飞满了春日的小洲，各种鲜花开遍了芬芳的田野。`, interpretation: `这是南朝诗人谢朓登上三山眺望京城建康时写的。谢朓是著名的山水诗人，这几句是他眺望所见的美景。他用两个历史人物（王粲、潘岳）远望京城的典故开头，立刻让人感受到他对京城的依恋。接着连用四个比喻：屋檐如飞、晚霞像彩绸、江水像白绢，把眼前景色写得绚丽又宁静。后世李白那句“余霞散成绮，澄江静如练”几乎原封不动地化用了这里，可见谢朓写景多么精妙，影响有多大！` }] },
  { id: 61, title: "七哀诗（节选）",
    author: "曹植",
    dynasty: "三国",
    category: "三国",
    summary: "君若清路尘，妾若浊水泥，浮沉各异势，会合何时谐",
    tags: "三国,情感",
    color: "#f97316",
    sections:[    { id: 1, title: "七哀诗（节选）", original: `明月照高楼，流光正徘徊。
上有愁思妇，悲叹有余哀。
君若清路尘，妾若浊水泥。
浮沉各异势，会合何时谐。
愿为西南风，长逝入君怀。`, translation: `明亮的月光照在高高的楼上，月光来回地流动着。楼上有个满心忧愁的妇人，一声声悲叹，满怀哀伤。夫君就像路上飞扬的清尘，妾身就像水里沉下的浊泥。尘土飞扬、泥水下沉，各有各的去向，什么时候才能再相会呢？我真愿化作一阵西南风，一直吹进夫君的怀抱里。`, interpretation: `这首诗写于三国乱世，曹植被哥哥曹丕猜忌，屡遭迫害，诗中那位"愁思妇"正是他自己的影子。明月高楼的清冷景象，象征着孤独与思念；"清尘"和"浊水泥"用得很妙——一个轻扬天上，一个沉落水里，明明是同一种东西，却因为处境不同再也到不了一起。最后他宁愿化作一阵风扑进亲人怀抱，多么让人心疼！这首诗最早用"明月"写愁思，对后来曹雪芹写《葬花吟》都产生了影响呢。` }] },
  { id: 62, title: "咏荆轲（节选）",
    author: "陶渊明",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "其人虽已没，千载有余情",
    tags: "魏晋南北朝,经典",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "咏荆轲（节选）", original: `燕丹善养士，志在报强嬴。
君子死知己，提剑出燕京。
雄发指危冠，猛气冲长缨。
登车何时顾，飞盖入秦庭。
其人虽已没，千载有余情。`, translation: `燕太子丹喜欢收养有才能的人，心里想着要向强大的秦国报仇。君子愿意为知己的朋友去死，荆轲提起了宝剑就离开了燕国京城。他气得头发直竖，把高高的帽子都快顶飞了，猛烈的豪气简直要把帽带都冲断。登上车子，他什么时候回头看过呢？驾着飞快的马车直向秦国的朝廷冲去。这个人虽然已经死去了，但过了千百年，他的豪情壮志依然让人感动。`, interpretation: `这首诗写于东晋时期，陶渊明平日里像个温柔的田园诗人，但他心里其实藏着对英雄的敬佩。秦国灭了六国，燕国太子丹为了报仇，派出勇士荆轲去刺杀秦王，结果失败了，荆轲也牺牲了。陶渊明最厉害的地方，是用"雄发指危冠，猛气冲长缨"这两句，把荆轲出发前那种又愤怒又悲壮的英雄气概写得活灵活现，好像你都能看见他气得头发炸起来的样子。这首诗让荆轲的故事流传得更广，连陶渊明这样不爱打打杀杀的诗人，都忍不住为他写诗点赞，可见真正的英雄精神是不分时代的！` }] },
  { id: 63, title: "五柳先生传（节选）",
    author: "陶渊明",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "好读书不，求甚解每，有会意便，欣然忘食",
    tags: "魏晋南北朝,经典",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "五柳先生传（节选）", original: `先生不知何许人也，宅边有五柳树，因以为号焉。
闲静少言，不慕荣利。
好读书，不求甚解；每有会意，便欣然忘食。
短褐穿结，箪瓢屡空，晏如也。`, translation: `五柳先生不知道是哪里的人。房屋旁边有五棵柳树，就用它做了自己的号。他性格安静，不爱说话，不羡慕荣华富贵。喜欢读书，不追求把每个字都弄懂；每当对书中的意思有所领会，就高兴得忘了吃饭。粗布短衣上打着补丁，饭篮和瓢里经常是空的，他依然安然自在。`, interpretation: `这是东晋大诗人陶渊明写的小传记，介绍了他想象中的自己——一位住在五棵柳树旁的先生。东晋时期官场黑暗，许多文人不愿同流合污，纷纷归隐田园。陶渊明借五柳先生，表达了自己安贫乐道、淡泊名利的志趣。文中"闲静少言，不慕荣利"是他最鲜明的形象，"好读书，不求甚解"更成为一种洒脱的阅读境界。短短几句，一位清贫却快乐的高人跃然纸上，影响了中国一千多年来读书人的精神追求。` }] },
  { id: 64, title: "野田黄雀行",
    author: "曹植",
    dynasty: "三国",
    category: "三国",
    summary: "高树多悲风，海水扬其波，利剑不在掌，结交何须多",
    tags: "三国,感怀",
    color: "#f97316",
    sections:[    { id: 1, title: "野田黄雀行", original: `高树多悲风，海水扬其波。
利剑不在掌，结交何须多。
不见篱间雀，见鹞自投罗。
罗家得雀喜，少年见雀悲。
拔剑捎罗网，黄雀得飞飞。`, translation: `高高的树梢上，悲凉的风呼呼地吹过。
海水翻涌着，卷起了层层波浪。
手中没有锋利的宝剑，
交朋友又何必太多？
你看那篱笆间的小雀，
正被鹞鹰追着，一头扎进了罗网。
设罗网的人逮到小雀真开心，
可少年看见了却心里发慌。
他拔出手中的剑，砍向那罗网，
黄雀挣脱出来，扑棱棱地飞向远方。`, interpretation: `这首诗写于三国时期，曹植的哥哥曹丕当上了皇帝，对他处处猜忌打压，他觉得有才能却没地方施展，就像被人关在笼子里一样憋屈。所以诗里的"利剑不在掌"其实是在说他自己——空有一身本事，却没人让他发挥。整首诗用"少年救雀"的小故事来打比方，讲的就是有本事的人应该去帮助那些遇到困难的人。曹植这种想冲破束缚、帮助弱者的心情，让这首诗读起来特别动人。后来"拔剑捎罗网"还成了名句，人们用它来形容路见不平、拔刀相助的勇敢。` }] },
  { id: 65, title: "赠从弟",
    author: "刘桢",
    dynasty: "三国",
    category: "三国",
    summary: "亭亭山上松，瑟瑟谷中风，风声一何盛，松枝一何劲",
    tags: "三国,咏物",
    color: "#f97316",
    sections:[    { id: 1, title: "赠从弟", original: `亭亭山上松，瑟瑟谷中风。
风声一何盛，松枝一何劲。
冰霜正惨凄，终岁常端正。
岂不罹凝寒，松柏有本性。`, translation: `高高的山上长着一棵挺拔的松树，山谷里吹来阵阵瑟瑟的寒风。风声是多么的猛烈啊，松树的枝干却是多么的刚劲！冰霜袭来，四周一片凄惨，但松树一年到头都保持着端端正正的姿态。难道松树不怕遭遇严寒吗？不是的，这是松柏天生就有的本性啊。`, interpretation: `这首诗是东汉末年刘桢写给堂弟的。当时社会动荡，许多人为了保命失去了气节，诗人便借松树来勉励堂弟要坚守品格。诗中最核心的意象就是"松柏"——它们不畏风霜、端正挺立，正是坚强不屈精神的象征。全诗以"松"和"风""冰霜"对比，一刚一柔，一烈一坚，写得刚健有力，朗朗上口。这种"托物言志"的手法后来被许多诗人沿用，比如陶渊明写菊、于谦写石灰，都受到了它的启发。` }] },
  { id: 66, title: "燕歌行",
    author: "曹丕",
    dynasty: "三国",
    category: "三国",
    summary: "秋风萧瑟天气凉，草木摇落露为霜，群燕辞归鹄南翔",
    tags: "三国,情感",
    color: "#f97316",
    sections:[    { id: 1, title: "燕歌行", original: `秋风萧瑟天气凉，草木摇落露为霜。
群燕辞归鹄南翔，贱妾茕茕守空房。
忧来思君不敢忘，不觉泪下沾衣裳。`, translation: `秋风阵阵吹来，天气越来越凉，树木花草枯黄凋零，露水也变成了白霜。一群群燕子和大雁都飞回南方去了。只有我孤零零地守在空荡荡的房间里。想念你的忧愁涌上心头，我怎么也不敢忘。不知不觉，眼泪就流了下来，打湿了衣裳。`, interpretation: `这是曹丕写给远方丈夫的思念之诗，背景是战乱年代，许多夫妻被迫分离。诗中用了秋风、霜冻、归燕这些秋天特有的景象，暗示时间流逝和别人的团聚，反衬出女主人公的孤独。最妙的是“群燕辞归”和“茕茕守空房”的对比，热闹是别人的，她只剩自己。曹丕把女子悄悄落泪写得又美又让人心疼，是后世思妇诗的典范，连“贱妾茕茕守空房”都成了名句。` }] },
  { id: 67, title: "七步诗",
    author: "曹植",
    dynasty: "三国",
    category: "三国",
    summary: "煮豆燃豆萁，豆在釜中泣，本是同根生，相煎何太急",
    tags: "三国,经典",
    color: "#f97316",
    sections:[    { id: 1, title: "七步诗", original: `煮豆燃豆萁，豆在釜中泣。
本是同根生，相煎何太急。`, translation: `煮豆子用豆秸来燃烧，
豆子在锅里哭泣。
我们本来是同一条根上长出来的，
为什么要这么急迫地煎熬我呢？`, interpretation: `这首诗写于三国时期，相传曹植的哥哥曹丕当了皇帝后，忌惮弟弟的才华，命他七步之内作诗，否则就要处死他。曹植便吟出了这首诗。诗中用'豆萁'比喻曹丕，用'豆'比喻自己，'同根生'点明兄弟手足之情，控诉了哥哥对自己的迫害。整首诗用比喻的手法，把兄弟相残比作豆秸煮豆，形象又凄凉，最后一句'相煎何太急'流传千古，成为描写骨肉相残的经典名句。这首诗也让我们明白，家人之间应该相亲相爱，不要互相伤害。` }] },
  { id: 68, title: "白马篇",
    author: "曹植",
    dynasty: "三国",
    category: "三国",
    summary: "捐躯赴国难，视死忽如归",
    tags: "三国,经典",
    color: "#f97316",
    sections:[    { id: 1, title: "白马篇", original: `白马饰金羁，连翩西北驰。
弃身锋刃端，性命安可怀。
父母且不顾，何言子与妻。
名编壮士籍，不得中顾私。
捐躯赴国难，视死忽如归。`, translation: `骑着白马配上金色的马笼头，跨上马背向着西北飞奔而去。宁可把身体丢在刀剑锋刃之下，怎能贪恋自己的性命？为了解救国家的危难甘愿献出生命，把死亡看得像回家一样平常。`, interpretation: `这首诗写于三国时期，曹植的哥哥曹丕刚当上皇帝，他心怀报国之志却无处施展，于是借一个少年英雄的形象表达心愿。诗中最精彩的是「白马饰金羁」——一匹白马配上金马鞍，多么英武帅气！少年骑着它冲向战场，把为国家牺牲看得像回家一样平常。这种豪迈的气概和强烈的爱国情怀，让这首诗成为千古名篇，激励了一代又一代中国人。尤其是「视死忽如归」这句，至今读来仍让人热血沸腾！` }] },
  { id: 69, title: "行路难（节选）",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "金樽清酒斗十千，玉盘珍羞直万钱，停杯投箸不能食，拔剑四顾心茫然，长风破浪会有时，直挂云帆济沧海",
    tags: "唐,励志",
    color: "#f59e0b",
    sections:[    { id: 1, title: "行路难（节选）", original: `金樽清酒斗十千，玉盘珍羞直万钱。
停杯投箸不能食，拔剑四顾心茫然。
欲渡黄河冰塞川，将登太行雪满山。
闲来垂钓碧溪上，忽复乘舟梦日边。
行路难！行路难！多歧路，今安在？
长风破浪会有时，直挂云帆济沧海。`, translation: `金杯里装着的美酒，一斗就值十千钱。玉盘里盛着的佳肴，价值更是高达万钱。可是我却放下酒杯，扔掉筷子，什么也吃不下去。拔出宝剑，朝着四面八方张望，心里却感到一片茫然。想要渡过黄河吧，冰雪却冻结了河流；想要登上太行山吧，大雪又封住了山峰。唉，总有一天，我会乘着长风破浪前行，到那时，我定要高高挂起云帆，径直渡过那浩瀚的大海！`, interpretation: `这是李白在仕途受挫、被迫离开长安时写的。诗人满腹才华却报国无门，心情郁闷极了。诗里有两样特别有意思的意象：一是“冰塞黄河”“雪满太行”，表面写自然，其实是他心里觉得前路全被堵住了；二是“长风破浪”“云帆济海”，这是他最出名的句子之一，鼓励了无数遇到困难的朋友！一千多年来，每次有人觉得撑不下去了，都会想起这两句——再难的路，也一定会有云开月明的那一天。` }] },
  { id: 70, title: "梦游天姥吟留别（节选）",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "安能摧眉，折腰事权，贵使我不，得开心颜",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "梦游天姥吟留别（节选）", original: `世间行乐亦如此，古来万事东流水。
别君去兮何时还，且放白鹿青崖间。
须行即骑访名山，安能摧眉折腰事权贵，使我不得开心颜。`, translation: `人世间的欢乐也像梦一样，古往今来所有事情都像东流的水一去不回头。我要离开你们了，什么时候才能回来呢？先把白鹿放养在青翠的山崖之间，想要出行的时候就骑着它去寻访名山。怎么能低头弯腰去伺候那些有权有势的人，让我心里不高兴呢？`, interpretation: `这是李白被权贵排挤出京后，在东鲁将要南游时写下的一首长诗的结尾。他把人世的富贵看作一场梦，认为万事像流水一样不可挽留，所以决心骑上白鹿去游历四方。这几句最厉害的就是最后那句'安能摧眉折腰事权贵，使我不得开心颜'——我怎么能够低眉弯腰去巴结当官的，让自己不开心呢！这种不向权贵低头的傲气，影响了后来很多文人，成了千古传诵的名句。` }] },
  { id: 71, title: "闻王昌龄左迁龙标遥有此寄",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "杨花落尽子规啼，闻道龙标过五溪，我寄愁心与明月，随君直到夜郎西",
    tags: "唐,送别",
    color: "#f59e0b",
    sections:[    { id: 1, title: "闻王昌龄左迁龙标遥有此寄", original: `杨花落尽子规啼，闻道龙标过五溪。
我寄愁心与明月，随君直到夜郎西。`, translation: `杨花都落光了，杜鹃在不停地啼叫。我听说你被贬到龙标，要经过那五道溪水。我把满心的愁思寄托给天上的明月，让它跟着你一直走到夜郎的西边。`, interpretation: `这首诗写于唐玄宗天宝年间，当时李白听说好友王昌龄被贬到偏远的龙标（今湖南怀化），心中十分牵挂。诗里有两个特别美的意象：飘落的杨花和啼叫的子规（杜鹃），杨花让人想到漂泊无依，杜鹃的叫声在古诗里常代表伤心。'我寄愁心与明月'是千古名句，李白把自己的思念托付给月亮，让月亮陪着朋友走完远路，浪漫又温暖。这种把月亮当作信使的写法，后来很多人都在学呢！` }] },
  { id: 72, title: "古朗月行（节选）",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "小时不识月，呼作白玉盘，又疑瑶台镜，飞在青云端",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "古朗月行（节选）", original: `小时不识月，呼作白玉盘。
又疑瑶台镜，飞在青云端。
仙人垂两足，桂树何团团。
白兔捣药秋复春，姮娥孤栖与谁怜。`, translation: `小时候我不认识月亮，
把它叫作白色的玉盘。
又怀疑它是神仙宫里的一面镜子，
飞呀飞，挂在了高高的云端。`, interpretation: `这是李白小时候的一首小诗，写于盛唐时期，那是个连诗人都爱幻想的浪漫年代。诗中用了两个特别美的意象——白玉盘和瑶台镜，把圆圆的月亮比作吃饭的玉盘，又比作神仙用的镜子，想象大胆又可爱。最妙的是一个"飞"字，月亮好像长了翅膀一样飘到云端，童趣十足。这首诗后来常被选进儿童启蒙读物，连大人都觉得"呼作白玉盘"这一句天真得让人发笑又让人羡慕。` }] },
  { id: 73, title: "把酒问月（节选）",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "青天有月来几时，我今停杯一问之，人攀明月不可得，月行却与人相随",
    tags: "唐,哲理",
    color: "#f59e0b",
    sections:[    { id: 1, title: "把酒问月（节选）", original: `青天有月来几时？我今停杯一问之。
人攀明月不可得，月行却与人相随。`, translation: `青天上挂着那一轮明月，它是从什么时候开始有的呢？我李白现在停下酒杯，要问一问月亮。人想要攀上青天去摘月亮，那是不可能做到的事，可是月亮却会跟着人一起移动，走到哪儿它就跟到哪儿。`, interpretation: `这是李白《把酒问月》中最有名的一段。李白在月亮下端着酒杯，忽然对天上的月亮产生了好奇：月亮是什么时候有的呢？于是他停下酒杯，认认真真地向月亮发问。接着他发现了一个有趣的现象——人想爬到月亮上去够不着，但月亮却像好朋友一样，你走到哪儿它就跟到哪儿。这首诗写于盛唐时期，李白一生爱月亮、写月亮，这首就是他对着月亮一边喝酒一边思考人生的名篇。它最厉害的地方是把"问月"写得又浪漫又有哲理，让小朋友也能感受到：原来抬头看月亮，也可以是一件很有诗意的事。` }] },
  { id: 74, title: "月下独酌（节选）",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "花间一壶酒，独酌无相亲，举杯邀明月，对影成三人",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "月下独酌（节选）", original: `花间一壶酒，独酌无相亲。
举杯邀明月，对影成三人。
月既不解饮，影徒随我身。
暂伴月将影，行乐须及春。`, translation: `我在花丛中间摆下一壶好酒，自个儿喝着，身边没有一个亲近的人。只好举起杯子邀请天上的明月一起来喝，再加上我的影子，咱们仨凑成一桌啦！`, interpretation: `这首诗写于一个安静的夜晚，李白一个人喝酒觉得很孤单。可他是个乐天派呀，想了个绝妙的主意：把天上的月亮和自己的影子拉来当朋友，一下子变成“三个人”喝酒了！这种丰富的想象力是李白诗歌最迷人的地方。他明明很孤独，却写出了热闹又有趣的感觉，让人读着读着就笑了。这几句诗流传了一千多年，小朋友写作文时也可以学学这种“变无聊为有趣”的妙招哦！` }] },
  { id: 75, title: "登金陵凤凰台",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "凤凰台上凤凰游，凤去台空江自流，吴宫花草埋幽径，晋代衣冠成古丘",
    tags: "唐,感怀",
    color: "#f59e0b",
    sections:[    { id: 1, title: "登金陵凤凰台", original: `凤凰台上凤凰游，凤去台空江自流。
吴宫花草埋幽径，晋代衣冠成古丘。
三山半落青天外，二水中分白鹭洲。
总为浮云能蔽日，长安不见使人愁。`, translation: `凤凰台上，曾经有凤凰鸟儿来游玩。凤凰飞走了，台上空空荡荡，只有长江水独自流淌。当年吴国的宫殿已经倒塌，花草野藤掩埋了幽静的小路。晋代的达官贵人们，也都变成了一座座古坟。都是因为天上的浮云遮住了太阳，站在这里看不见长安城，真让人心里发愁啊。`, interpretation: `这是李白在仕途不顺、离开长安后，登临金陵凤凰台时写下的诗。当时他被排挤出朝廷，怀才不遇，心中十分苦闷。诗中借凤凰台、长江、吴国宫殿、晋代古墓等景象，感慨繁华终会消逝、英雄也会老去。"总为浮云能蔽日"一句，巧妙地借用"浮云遮日"来比喻奸臣当道，遮挡了贤臣。这首诗对仗工整，气势雄浑，被誉为李白登临之作中可与崔颢《黄鹤楼》比肩的千古名篇。` }] },
  { id: 76, title: "子夜吴歌·秋歌",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "长安一片月，万户捣衣声，秋风吹不尽，总是玉关情，何日平胡虏，良人罢远征",
    tags: "唐,边塞",
    color: "#f59e0b",
    sections:[    { id: 1, title: "子夜吴歌·秋歌", original: `长安一片月，万户捣衣声。
秋风吹不尽，总是玉关情。
何日平胡虏，良人罢远征。`, translation: `长安城笼罩在一片明月的清光里，千家万户传来阵阵捣衣的声音。秋风吹啊吹，吹不尽的是对远方玉门关的深深思念。什么时候才能平定北方的胡人，让我的丈夫不再去远方征战？`, interpretation: `这首诗写于盛唐时期，是李白乐府诗中的名篇。诗人借秋夜捣衣的声响，描绘了长安城里妻子们思念远方丈夫的深情。捣衣声声、月光皎洁、秋风阵阵，这些意象交织在一起，勾勒出一幅思妇盼归的动人画面。诗中既有对征人远征的担忧，也有对和平生活的渴望，最后两句直抒胸臆，问出了千万百姓的心声。这首诗语言质朴、情感真挚，尤其是'长安一片月，万户捣衣声'两句，以明月和捣衣声营造出广阔而深远的意境，千百年来广为传诵。` }] },
  { id: 77, title: "宣州谢朓楼饯别校书叔云（节选）",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "弃我去者昨日之日不可留乱我心者今日之日多烦忧抽刀断水水更流举杯消愁愁更愁",
    tags: "唐,感怀",
    color: "#f59e0b",
    sections:[    { id: 1, title: "宣州谢朓楼饯别校书叔云（节选）", original: `弃我去者，昨日之日不可留。
乱我心者，今日之日多烦忧。
长风万里送秋色，对此可以酣高楼。
蓬莱文章建安骨，中间小谢又清发。
俱怀逸兴壮思飞，欲上青天览明月。
抽刀断水水更流，举杯消愁愁更愁。
人生在世不称意，明朝散发弄扁舟。`, translation: `抛弃我而去的，是昨天的日子，昨天已经过去，留也留不住。扰乱我内心的，是今天的日子，今天又有太多烦恼和忧愁。万里长风把秋天的景色送来，面对这样的景色，我可以在高楼上畅快地喝酒。抽出刀来想斩断流水，水却流得更快；举起酒杯想消除愁苦，愁苦却变得更多。人生在世上，如果不能称心如意，不如明天就披散头发，驾着小船归隐江湖去吧。`, interpretation: `这是李白在宣州谢朓楼上为叔叔李云送别时写的诗。他一生渴望当大官、做大事，可总是不如愿，心里特别烦闷。诗里有两个特别有名的比喻：把愁比作流水，说拿刀去砍，水反而流得更急；举杯想借酒消愁，愁反而更多。小朋友有没有过这种感觉？越想忘掉一件不开心的事，它越忘不掉！不过李白最厉害的地方在于——他不只是叹气，最后一句忽然飞起来：管它呢，大不了明天披着头发去划船玩！这种从郁闷到洒脱的大转弯，就是李白诗歌最迷人的地方。` }] },
  { id: 78, title: "从军行",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "百战沙场碎铁衣，城南已合数重围，突营射杀呼延将，独领残兵千骑归",
    tags: "唐,战争",
    color: "#f59e0b",
    sections:[    { id: 1, title: "从军行", original: `百战沙场碎铁衣，城南已合数重围。
突营射杀呼延将，独领残兵千骑归。`, translation: `战士们在战场上身经百战，铁甲都破碎了。敌人已经重重包围了城南。他突然冲进敌营，射杀了敌将呼延。独自带领剩下的千名骑兵，杀出重围回到了军营。`, interpretation: `这首诗写于唐代，边疆战事频繁，许多将士奔赴沙场保家卫国。李白虽以浪漫诗闻名，但这首边塞诗却充满英雄气概。诗中最精彩的是'突营射杀'四个字——只见诗人笔下的大将如天神下凡，单枪匹马冲入敌阵，一箭射杀敌方首领呼延将，然后带着仅剩的千人骑兵从容突围。这是何等豪迈！短短四句，既有沙场厮杀的紧张，又有胜利归来的从容，'独领残兵千骑归'一句更是流传千古，成为描写英雄孤胆的经典名句。小朋友们读这首诗，闭上眼睛，是不是能想象出那位将军策马奔腾的威风模样？` }] },
  { id: 79, title: "丁督护歌",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "云阳上征去，两岸饶商贾，吴牛喘月时，拖船一何苦",
    tags: "唐,民生",
    color: "#f59e0b",
    sections:[    { id: 1, title: "丁督护歌", original: `云阳上征去，两岸饶商贾。
吴牛喘月时，拖船一何苦。
水浊不可饮，壶浆半成土。
一唱督护歌，心摧泪如雨。
万人凿磐石，无由达江浒。
君看石芒砀，掩泪悲千古。`, translation: `从云阳坐船往北逆流而上，去参加徭役。
河的两岸住着好多做生意的有钱人。
天气热得连吴地的水牛都对着月亮喘气，
可我这拉船的苦役，真是苦得没法说呀！`, interpretation: `这首诗是李白在唐玄宗天宝年间游历江苏时写的。诗很短，只有四句，却充满了对劳动人民的深深同情。当时朝廷征调百姓去服役运船，无论酷暑寒冬都得拖船前行。两岸的商贾有钱悠闲，岸上拖船的人却被热浪折磨得喘不过气，反差特别强烈。诗人用“吴牛喘月”这个巧妙的细节，把暑热难耐写得生动极了，让人一下子就能感受到那种辛苦。短短二十个字，却写尽了底层劳动者的辛酸，是李白诗歌中难得的关心民生疾苦的作品。` }] },
  { id: 80, title: "关山月（节选）",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "明月出天山，苍茫云海间，长风几万里，吹度玉门关",
    tags: "唐,边塞",
    color: "#f59e0b",
    sections:[    { id: 1, title: "关山月（节选）", original: `明月出天山，苍茫云海间。
长风几万里，吹度玉门关。
汉下白登道，胡窥青海湾。
由来征战地，不见有人还。
戍客望边色，思归多苦颜。
高楼当此夜，叹息未应闲。`, translation: `明亮的月亮从祁连山升起来了，它穿行在无边无际的云海之间。浩浩荡荡的春风飘过几万里，一直吹到了遥远的玉门关。`, interpretation: `这首诗写于盛唐时期，那时候许多诗人都有立功边疆的志向，李白也不例外。诗里有三个特别美的画面：圆月、雪山、云海，一开头就像一幅水墨画铺在眼前。"长风几万里"这个"几万里"用得特别妙，把春风写得又远又有劲儿，好像风儿真的能飞越整个大唐的疆土呢！短短四句，没有一个"思乡"的字，却让人忍不住想家，这就是李白的高明之处。后来"长风几万里，吹度玉门关"常被人引用来形容壮志豪情。` }] },
  { id: 81, title: "望岳",
    author: "杜甫",
    dynasty: "唐",
    category: "唐",
    summary: "会当凌绝顶，一览众山小",
    tags: "唐,励志",
    color: "#f59e0b",
    sections:[    { id: 1, title: "望岳", original: `岱宗夫如何？齐鲁青未了。
造化钟神秀，阴阳割昏晓。
荡胸生曾云，决眦入归鸟。
会当凌绝顶，一览众山小。`, translation: `巍峨的泰山到底有多雄伟呢？它苍翠的山色在齐鲁两地都望不尽。大自然把神奇和秀丽都集中到了这里，山峰的向阳一面明亮如清晨，背阴一面昏暗似傍晚，截然不同。山间层云升腾令人胸怀激荡，极目远眺，归林的飞鸟也映入眼帘。一定要登上泰山的顶峰，那时俯瞰群山，众山都会显得矮小。`, interpretation: `这首诗是杜甫二十四岁时漫游齐鲁地区所作，正是他年轻气盛、充满抱负的时期。全诗以一个'望'字贯穿，却不写登山，只写远望中的泰山，想象登顶的景象。诗人用'割'字写山势的高大，把山南山北的明暗分成两个世界，最妙的是最后两句'会当凌绝顶，一览众山小'，表达了年轻人敢于攀登高峰、俯视一切的雄心壮志。这两句后来成了千古名句，激励着无数人勇敢向前，挑战自我。整首诗没有一句'愁'字，处处洋溢着青年杜甫的豪情与自信。` }] },
  { id: 82, title: "蜀相",
    author: "杜甫",
    dynasty: "唐",
    category: "唐",
    summary: "出师未捷身先死，长使英雄泪满襟",
    tags: "唐,怀古",
    color: "#f59e0b",
    sections:[    { id: 1, title: "蜀相", original: `丞相祠堂何处寻？锦官城外柏森森。
映阶碧草自春色，隔叶黄鹂空好音。
三顾频烦天下计，两朝开济老臣心。
出师未捷身先死，长使英雄泪满襟。`, translation: `丞相的祠堂到哪里去找呢？就在锦官城外，柏树长得高大茂密的地方。绿草映照着台阶，一年春天自己来到；黄鹂隔着树叶白白地唱着好听的歌。刘备三次拜访他，商量的是统一天下的大计；辅佐两代君主，开创和守卫国家，是老臣的一片忠心。可惜他出兵打仗还没取得胜利，自己就先病死了。这让后代的英雄们想起来，常常眼泪沾湿了衣襟。`, interpretation: `这首诗写于杜甫客居成都的时候，那时他正过着漂泊困苦的生活。听说武侯祠就在城外，他便去寻访，写下这首诗。诗里有三个特别重要的画面：高大的柏树、空自鸣叫的黄鹂和让人落泪的祠堂。柏树象征诸葛亮伟大的品格永远长青；黄鹂叫声虽好听，却无人欣赏，比喻世人并不真正理解他。杜甫特别擅长用这种“热闹反衬孤独”的写法，前面写得越安静，后面英雄的眼泪就越让人心酸。‘出师未捷身先死，长使英雄泪满襟’这两句成了千古名句，每当人们想起那些尽心尽力、却没能完成心愿的人，都会想起这两句诗。` }] },
  { id: 83, title: "江村",
    author: "杜甫",
    dynasty: "唐",
    category: "唐",
    summary: "多病所须唯药物，微躯此外更何劳",
    tags: "唐,感怀",
    color: "#f59e0b",
    sections:[    { id: 1, title: "江村", original: `清江一曲抱村流，长夏江村事事幽。
自去自来梁上燕，相亲相近水中鸥。
老妻画纸为棋局，稚子敲针作钓钩。
多病所须唯药物，微躯此外更何劳。`, translation: `清澈的江水弯弯曲曲地绕着村子流淌。漫长的夏日里，江边小村庄样样事情都显得安闲宁静。屋梁上的燕子自由自在地飞来飞去，水中的鸥鸟成双成对地相互依偎嬉戏。`, interpretation: `这首诗写于杜甫晚年定居成都草堂时期，那时安史之乱已经结束，诗人终于过上了一段相对安定的生活。诗中描绘了一个宁静祥和的江边小村：清澈的江水环绕村庄，夏日漫长却悠闲自得，燕子自由飞舞，鸥鸟相伴成趣。核心意象是"清江""梁燕""水鸥"，处处透着人与自然的和谐。艺术上以白描手法写景，朴素自然却意境悠远。这首《江村》是杜甫难得的闲适之作，展现了诗圣在历经战乱沧桑后，对平凡安宁生活的珍惜与热爱，也让后人看到一代诗圣温柔平和的一面。` }] },
  { id: 84, title: "兵车行（节选）",
    author: "杜甫",
    dynasty: "唐",
    category: "唐",
    summary: "车辚辚马萧萧行人弓箭各在腰间君不见青海头古来白骨无人收",
    tags: "唐,战争",
    color: "#f59e0b",
    sections:[    { id: 1, title: "兵车行（节选）", original: `车辚辚，马萧萧，行人弓箭各在腰。
耶娘妻子走相送，尘埃不见咸阳桥。
牵衣顿足拦道哭，哭声直上干云霄。
道旁过者问行人，行人但云点行频。
或从十五北防河，便至四十西营田。
去时里正与裹头，归来头白还戍边。
边庭流血成海水，武皇开边意未已。
君不见，青海头，古来白骨无人收。
新鬼烦冤旧鬼哭，天阴雨湿声啾啾。`, translation: `战车轰隆隆地响，战马萧萧地叫，出征的士兵们把弓箭都挂在腰上。亲人们扯着衣服、跺着脚，拦在路中间放声大哭。哭声一直冲上了高高的云霄。你没看见吗？青海湖边那古战场上，从来都是白骨遍地没人收拾。新战死的鬼魂在诉说冤屈，旧战死的鬼魂也在哭嚎。到了阴天下雨的时候，就会听到鬼魂们啾啾地哭泣。`, interpretation: `这首诗写于唐朝天宝年间，那时候唐玄宗不断发动边境战争，老百姓被强行征召去打仗，亲人分别时哭得撕心裂肺。杜甫用“车辚辚、马萧萧”开头，光是声音就让人感到紧张；接着“牵衣顿足拦道哭”，七个字里有人物的动作和悲痛，画面感特别强。后半段从眼前送别转到青海古战场，借鬼哭来写战争的残酷，真是又可怕又让人心疼。这首诗最大的特点是用百姓的哭声说真话，所以被称为“诗史”，意思是杜甫的诗就像历史一样真实。后世写战争苦难的诗，很多都受了它的影响。` }] },
  { id: 85, title: "羌村三首（节选）",
    author: "杜甫",
    dynasty: "唐",
    category: "唐",
    summary: "峥嵘赤云西，日脚下平地，柴门鸟雀噪，归客千里至",
    tags: "唐,叙事",
    color: "#f59e0b",
    sections:[    { id: 1, title: "羌村三首（节选）", original: `峥嵘赤云西，日脚下平地。
柴门鸟雀噪，归客千里至。
妻孥怪我在，惊定还拭泪。
世乱遭飘荡，生还偶然遂。
邻人满墙头，感叹亦歔欷。
夜阑更秉烛，相对如梦寐。`, translation: `西边天空中翻卷着层层叠叠像山一样高的红云，太阳光从云缝里射下来，平地上洒满了光辉。柴门前鸟儿叽叽喳喳地叫个不停，原来是漂泊千里的人终于回家了。妻子和孩子们看到我竟然还活着，又惊讶又奇怪，等心情平静下来，又忍不住擦去惊喜的泪水。在这兵荒马乱的年代里四处漂泊，能够活着回来，实在是偶然的幸运啊。`, interpretation: `这首诗写于公元757年，那时安史之乱已经爆发两年多，杜甫历尽艰险终于回到家中。诗中最动人的是家人的反应：先是惊讶——怎么还活着？再是拭泪——原来是高兴的泪水。短短几行字，把战乱中普通百姓的悲欢写得让人鼻子发酸。“妻孥怪我在，惊定还拭泪”成了千古名句，因为它说出了一个朴素的真理：和平年代回家是平常事，乱世里活着回家就是奇迹。杜甫最了不起的地方，就是能把这种真实的小情感写得那么动人。` }] },
  { id: 86, title: "阁夜",
    author: "杜甫",
    dynasty: "唐",
    category: "唐",
    summary: "岁暮阴阳催短景，天涯霜雪霁寒宵，五更鼓角声悲壮，三峡星河影动摇",
    tags: "唐,感怀",
    color: "#f59e0b",
    sections:[    { id: 1, title: "阁夜", original: `岁暮阴阳催短景，天涯霜雪霁寒宵。
五更鼓角声悲壮，三峡星河影动摇。
野哭几家闻战伐，夷歌数处起渔樵。
卧龙跃马终黄土，人事依依漫寂寥。`, translation: `一年到了尽头，白天越来越短，黑夜却越来越长。
在这偏远的地方，寒冷的夜晚，雪停了，霜也化了。
五更天的时候，战鼓声和号角声响起，声音是那样悲壮。
抬头看，三峡上空的银河和星星的影子，随着水波一起轻轻摇晃。`, interpretation: `这首诗写在公元766年冬天，杜甫住在夔州。那时候他年纪大了，又生病，离开家乡很久，心里又愁又冷。诗里有一个特别有意思的地方：诗人听见的是打仗的鼓角声，看到的是天上摇晃的星星。地上的声音很悲壮，天上的影子在晃动——他把自己心里的不安，写进了天地之间。这首诗最厉害的就是把“小”和“大”放在一起：寒夜、霜雪是一点点大的；鼓角、星河是很大很大的。可是它们都让诗人觉得孤单又难过。后来“岁暮天寒”成了人们形容又冷又孤单的常用词，很多人都喜欢用。` }] },
  { id: 87, title: "长恨歌（节选）",
    author: "白居易",
    dynasty: "唐",
    category: "唐",
    summary: "回眸一笑百媚生，六宫粉黛无颜色，在天愿作比翼鸟，在地愿为连理枝，天长地久有时尽，此恨绵绵无绝期",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "长恨歌（节选）", original: `汉皇重色思倾国，御宇多年求不得。
杨家有女初长成，养在深闺人未识。
天生丽质难自弃，一朝选在君王侧。
回眸一笑百媚生，六宫粉黛无颜色。
春寒赐浴华清池，温泉水滑洗凝脂。
在天愿作比翼鸟，在地愿为连理枝。
天长地久有时尽，此恨绵绵无绝期。`, translation: `唐玄宗喜欢美人，想找一位倾国倾城的绝世佳人。统治天下这么多年，一直没能找到。天生美丽的人，怎么舍得让自己埋没呢？有一天，她被选进宫，来到了君王身边。她回头微微一笑，千娇百媚立刻显现，六宫里所有的妃子都失去了光彩。我们只愿在天上做那比翼双飞的鸟儿，在地上做那枝干相连的树枝。可是啊，天再长地再久也有尽头，这份思念的愁苦啊，却永远没有结束的时候。`, interpretation: `这首诗写于唐朝，写的是唐玄宗和杨贵妃的爱情故事。当时唐玄宗宠爱杨贵妃，后来安史之乱爆发，杨贵妃在马嵬坡离世，唐玄宗日夜思念。诗中最美的画面是“回眸一笑百媚生”，只一笑就让所有人黯然失色，想象力多丰富呀！而“天长地久有时尽，此恨绵绵无绝期”成了千古名句，意思是就算天地也有尽头，可这份遗憾却永远不会消失。后来很多戏剧、小说都从这个故事里取材，比如《长生殿》呢。` }] },
  { id: 88, title: "采莲曲",
    author: "白居易",
    dynasty: "唐",
    category: "唐",
    summary: "菱叶萦波荷飐风，荷花深处小船通，逢郎欲语低头笑，碧玉搔头落水中",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "采莲曲", original: `菱叶萦波荷飐风，荷花深处小船通。
逢郎欲语低头笑，碧玉搔头落水中。`, translation: `菱叶漂浮在水面上，荷叶在风中轻轻摇摆。荷花丛深处，有一只小船悄悄穿过。船上的姑娘遇见了心上人，正想开口说话，却害羞地低下头笑了一下。没想到头上的碧玉簪子一不小心掉进了水里。`, interpretation: `这首小诗出自唐代大诗人白居易之手，写的是江南水乡采莲的场景。唐代江南水乡生活富足，少女们常在夏日划着小船去采莲，诗人便用细腻的笔触捕捉了一个有趣的小片段。诗中最妙的是“欲语低头笑”这五个字，把小姑娘见到意中人时又惊喜又害羞的模样写得活灵活现。整首诗短短四句，有菱叶、有荷花、有风、有水、有人，构成了一幅清新又俏皮的水乡风情画。“碧玉搔头落水中”成了经典名句，让人读了忍不住会心一笑。` }] },
  { id: 89, title: "少年行",
    author: "王维",
    dynasty: "唐",
    category: "唐",
    summary: "新丰美酒斗十千，咸阳游侠多少年，相逢意气为君饮，系马高楼垂柳边",
    tags: "唐,边塞",
    color: "#f59e0b",
    sections:[    { id: 1, title: "少年行", original: `新丰美酒斗十千，咸阳游侠多少年。
相逢意气为君饮，系马高楼垂柳边。`, translation: `新丰出产的美酒一斗就要一万钱，咸阳城里游荡的侠客大多正是少年。他们偶然相遇，彼此意气相投，便拉你一起痛快畅饮，把马拴在高楼旁边、垂柳依依之处。`, interpretation: `这首诗写于盛唐时期，当时国力强盛，百姓充满自信与豪情，年轻人尤其向往建功立业、行走江湖。诗中没有刀光剑影，却处处透着少年侠客的勃勃生气——美酒、骏马、高楼、垂柳，组成一幅明丽鲜亮的画面。艺术上，王维用"美酒""游侠""意气"几个词，就把少年的豪爽劲儿勾了出来，语言明快，节奏铿锵。"相逢意气为君饮"一句尤其传神，成了后世描写豪情相遇的经典名句，常被引用来表达知己相逢的痛快。` }] },
  { id: 90, title: "登乐游原",
    author: "李商隐",
    dynasty: "唐",
    category: "唐",
    summary: "向晚意不适，驱车登古原，夕阳无限好，只是近黄昏",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "登乐游原", original: `向晚意不适，驱车登古原。
夕阳无限好，只是近黄昏。`, translation: `傍晚的时候，我心情不太好。于是坐上车，登上乐游原去看看风景。哇，那夕阳真是美极了！可惜呀，这么美的景色，却快要天黑了。`, interpretation: `这首诗写于李商隐晚年，当时唐朝已经快走到尽头，他心里装着很多忧国忧民的事，却没有人能理解他。一个傍晚，他心情不好，独自开车（那时候是马车哦）爬上乐游原想散散心。结果一抬头，看见了超级美的夕阳！可是这么美的景色，偏偏出现在快要天黑的时候，让人又惊喜又难过。后人最喜欢的就是最后两句——'夕阳无限好，只是近黄昏'，现在我们还经常用这两句诗来形容美好的事物总是特别短暂，要好好珍惜呢！` }] },
  { id: 91, title: "无题",
    author: "李商隐",
    dynasty: "唐",
    category: "唐",
    summary: "相见时难别亦难，东风无力百花残，春蚕到死丝方尽，蜡炬成灰泪始干",
    tags: "唐,爱情",
    color: "#f59e0b",
    sections:[    { id: 1, title: "无题", original: `相见时难别亦难，东风无力百花残。
春蚕到死丝方尽，蜡炬成灰泪始干。
晓镜但愁云鬓改，夜吟应觉月光寒。
蓬山此去无多路，青鸟殷勤为探看。`, translation: `我们难得见上一面，分别时更是难舍难分。暮春时节，东风柔弱无力，百花已经凋残。春蚕直到死去，蚕丝才能吐完；蜡烛烧成了灰，蜡泪才会流干。清晨对镜梳妆，只担忧如云的鬓发渐渐变白；夜晚独自吟诗，应感到月光冷冷清清。蓬莱山离这里没有多少路程，但愿有青鸟使者，殷勤地替我前去探望。`, interpretation: `这首诗写于晚唐，那时候朝廷里党派争斗很厉害，李商隐心里苦闷，就把一腔真情写进了爱情诗里。诗里有几个特别美的意象：春蚕吐丝、蜡烛流泪，比喻爱一个人愿意付出一切，哪怕到死才肯罢休；蓬山是传说中海上的仙山，青鸟是西王母的信使，代表对心上人深深的思念。这两句“春蚕到死丝方尽，蜡炬成灰泪始干”后来成了千古名句，常被用来形容老师对学生无私的奉献、医生对病人的付出，或者人们对待事业的忠诚。这首诗最厉害的地方是“意在言外”，明明写的是爱情，却又像在说人生、说理想，难怪一千多年来人人都爱读它。` }] },
  { id: 92, title: "霜月",
    author: "李商隐",
    dynasty: "唐",
    category: "唐",
    summary: "初闻征雁已无蝉，百尺楼高水接天，青女素娥俱耐冷，月中霜里斗婵娟",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "霜月", original: `初闻征雁已无蝉，百尺楼高水接天。
青女素娥俱耐冷，月中霜里斗婵娟。`, translation: `刚听到大雁南飞的叫声，蝉儿已经不再鸣叫。登上百尺高楼远望，水天相接连成一片。青女和嫦娥都能忍受寒冷，在月光和霜华里比试着谁更美丽动人。`, interpretation: `这首诗写于晚唐，李商隐借深秋夜晚的霜月之景，表达自己清高孤傲的情怀。当时诗人处境不佳，但他没有直接抱怨，而是用浪漫的想象来排遣愁绪。诗中最妙的是最后两句：霜神青女和月中嫦娥都“不怕冷”，在清冷的环境里争相比美。这种把寒冷写得美丽动人的手法，既展现了诗人高洁的品格，也让整首诗充满梦幻色彩。李商隐擅长用典故和想象，这首诗短短四句却意境开阔，是唐诗中写秋夜霜月的佳作。` }] },
  { id: 93, title: "从军行·其四",
    author: "王昌龄",
    dynasty: "唐",
    category: "唐",
    summary: "青海长云暗雪山，孤城遥望玉门关，黄沙百战穿金甲，不破楼兰终不还",
    tags: "唐,边塞",
    color: "#f59e0b",
    sections:[    { id: 1, title: "从军行·其四", original: `青海长云暗雪山，孤城遥望玉门关。
黄沙百战穿金甲，不破楼兰终不还。`, translation: `青海湖上的长云把雪山都遮得暗暗的，站在孤零零的城里，远远能望见玉门关。在黄沙里打了无数仗，盔甲都磨穿了，但是不打败敌人，我们绝不回家！`, interpretation: `这首诗写于唐朝，那时候边境常常打仗，战士们要保家卫国。王昌龄用'青海''雪山''黄沙''孤城'这些边塞景物，画出了一幅又远又冷又孤凉的画面，让小朋友们闭上眼睛就能感受到边疆的艰苦。最厉害的是后两句——'黄沙百战穿金甲，不破楼兰终不还'，意思是打了一百场仗，铠甲都被射穿了，但战士们还是不后退，发誓不打败敌人绝不回家！这种又苦又勇敢的精神特别让人感动，后来'不破楼兰终不还'还成了千古名句，被很多人引用呢。` }] },
  { id: 94, title: "从军行·其五",
    author: "王昌龄",
    dynasty: "唐",
    category: "唐",
    summary: "大漠风尘日色昏，红旗半卷出辕门，前军夜战洮河北，已报生擒吐谷浑",
    tags: "唐,边塞",
    color: "#f59e0b",
    sections:[    { id: 1, title: "从军行·其五", original: `大漠风尘日色昏，红旗半卷出辕门。
前军夜战洮河北，已报生擒吐谷浑。`, translation: `广袤的沙漠里，风卷沙尘，天空中的太阳都显得昏暗。战士们高举着红旗，旗子半卷着走出了军营大门。前方的部队昨晚在洮河北边和敌人交战，捷报已经传来：活捉了敌军的首领吐谷浑！`, interpretation: `这首诗写于盛唐时期，那时候唐朝国力强盛，边疆战事频繁，王昌龄多次去西北边塞，亲眼见过战场，所以写得特别真实生动。诗里有几个特别有画面感的词：漫天的'大漠风尘'、飞舞的'红旗'、夜色中的'洮河'，短短四句就像一部小电影，让人先看到出征时的紧张，再听到前线的战报。写法上最妙的是'不见战斗，只听捷报'，不写怎么打仗，反而更有气势！最后一句'已报生擒吐谷浑'成了千古名句，常被用来形容打了大胜仗，是小朋友写作文时也能用上的好句子哦。` }] },
  { id: 95, title: "采莲曲",
    author: "王昌龄",
    dynasty: "唐",
    category: "唐",
    summary: "荷叶罗裙一色裁，芙蓉向脸两边开，乱入池中看不见，闻歌始觉有人来",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "采莲曲", original: `荷叶罗裙一色裁，芙蓉向脸两边开。
乱入池中看不见，闻歌始觉有人来。`, translation: `碧绿的荷叶和姑娘的裙子像是同一块布裁出来的，颜色一模一样。粉红的荷花在姑娘脸颊两旁盛开，好像花儿对着她的脸笑。姑娘们划着小船进了荷花池，人和花混在一起，分不清哪个是花哪个是人啦。只能听到一阵阵歌声，才知道原来有人在这里采莲呢。`, interpretation: `这首诗写于盛唐时期，王昌龄借采莲的场景，描绘江南水乡的美丽画面。诗人没有直接写人有多美，而是用荷叶比作罗裙、用荷花比作笑脸，把人和自然融为一体，这就是"以景写人"的高明之处。"乱入池中看不见，闻歌始觉有人来"是千古名句，写得特别有趣——人藏进了花海里，只能靠歌声才能发现她们，画面感十足，让人好像也闻到了荷香、听见了歌声呢！` }] },
  { id: 96, title: "闺怨",
    author: "王昌龄",
    dynasty: "唐",
    category: "唐",
    summary: "闺中少妇不知愁，春日凝妆上翠楼，忽见陌头杨柳色，悔教夫婿觅封侯",
    tags: "唐,情感",
    color: "#f59e0b",
    sections:[    { id: 1, title: "闺怨", original: `闺中少妇不知愁，春日凝妆上翠楼。
忽见陌头杨柳色，悔教夫婿觅封侯。`, translation: `深闺里的年轻妻子原本不知道什么是忧愁，春日里她精心打扮，登上翠绿的楼阁。忽然看见路边的杨柳已经绽出新绿，才后悔当初让丈夫去外面追求功名。`, interpretation: `这首诗写于盛唐时期，那时候许多男子都渴望建功立业、出人头地。诗人没有直接写思念，而是抓住一个瞬间：少妇打扮得漂漂亮亮去登楼，本是为了散心，可一看见路边的杨柳——那是古人送别时折来相赠的象征——心里顿时翻涌起对远行丈夫的思念。整首诗只写她从'不知愁'到'悔'的转变，可背后的孤独和牵挂全藏在里头了。尤其是'悔教夫婿觅封侯'一句，流传千年，成了表达思妇心情的经典名句。` }] },
  { id: 97, title: "燕歌行（节选）",
    author: "高适",
    dynasty: "唐",
    category: "唐",
    summary: "战士军前半死生，美人帐下犹歌舞，大漠穷秋塞草腓，孤城落日斗兵稀",
    tags: "唐,边塞",
    color: "#f59e0b",
    sections:[    { id: 1, title: "燕歌行（节选）", original: `战士军前半死生，美人帐下犹歌舞。
大漠穷秋塞草腓，孤城落日斗兵稀。
身当恩遇常轻敌，力尽关山未解围。
铁衣远戍辛勤久，玉箸应啼别离后。
少妇城南欲断肠，征人蓟北空回首。
边庭飘飖那可度，绝域苍茫更何有。
杀气三时作阵云，寒声一夜传刁斗。
相看白刃血纷纷，死节从来岂顾勋。
君不见沙场征战苦，至今犹忆李将军。`, translation: `战士们在军队前面拼死作战，伤亡惨重；将军的营帐里，美人却还在唱歌跳舞。大沙漠到了深秋，边塞的草儿枯萎发黄。孤零零的城池上，太阳快落山了，还能打仗的士兵越来越少。`, interpretation: `这首诗写于唐玄宗统治后期，那时候皇帝喜欢打仗，大将们却只顾自己享乐，不管士兵死活。诗人高适用“战士”和“美人”做对比，一个在前线拼命，一个在后营享乐，看得让人又心疼又生气！“大漠”“孤城”“落日”这些画面特别苍凉，让人觉得战场好悲壮。后来“战士军前半死生，美人帐下犹歌舞”成了千古名句，专门用来批评那些不顾士兵死活的人。` }] },
  { id: 98, title: "白雪歌送武判官归京（节选）",
    author: "岑参",
    dynasty: "唐",
    category: "唐",
    summary: "忽如一夜春风来，千树万树梨花开",
    tags: "唐,边塞",
    color: "#f59e0b",
    sections:[    { id: 1, title: "白雪歌送武判官归京（节选）", original: `北风卷地白草折，胡天八月即飞雪。
忽如一夜春风来，千树万树梨花开。
散入珠帘湿罗幕，狐裘不暖锦衾薄。
将军角弓不得控，都护铁衣冷难着。
瀚海阑干百丈冰，愁云惨淡万里凝。
中军置酒饮归客，胡琴琵琶与羌笛。
纷纷暮雪下辕门，风掣红旗冻不翻。
轮台东门送君去，去时雪满天山路。
山回路转不见君，雪上空留马行处。`, translation: `北风呼啸着卷过大地，把白草都吹折了。西北边塞的天气，到了八月就开始下雪。这一夜，好像突然吹来了春风，一夜之间，千万棵梨树全都开满了白色的花。雪花飘进珠帘，打湿了丝绸帐幔。穿着狐皮大衣都不觉得暖和，锦缎被子也显得太薄了。山路曲折，绕来绕去，就看不见你的身影了。雪地上只留下你骑马走过的蹄印。`, interpretation: `这是唐代边塞诗人岑参的名篇，写于他送别朋友回长安的雪夜。诗人长期戍守边疆，熟悉那里的苦寒生活。开篇就让你感受边疆烈风大雪的厉害：八月就飞雪，连最好的狐裘锦被都挡不住寒冷。最妙的是中间四句——他不说雪花像什么，偏说像春风里盛开的梨花！这正是千古传诵的名句。春天象征温暖，梨花代表美好，诗人用最美的春景来形容冷酷的寒冬，正是边塞诗“以乐景写哀情”的绝妙手法。结尾目送朋友远去，只剩雪中蹄印，余味无穷。` }] },
  { id: 99, title: "送杜少府之任蜀州",
    author: "王勃",
    dynasty: "唐",
    category: "唐",
    summary: "海内存知己，天涯若比邻，无为在歧路，儿女共沾巾",
    tags: "唐,送别",
    color: "#f59e0b",
    sections:[    { id: 1, title: "送杜少府之任蜀州", original: `城阙辅三秦，风烟望五津。
与君离别意，同是宦游人。
海内存知己，天涯若比邻。
无为在歧路，儿女共沾巾。`, translation: `京城长安被三秦大地护卫着，（遥望）你要去的蜀州啊，只见一片风烟迷蒙。我和你就要分别了，心里有说不完的话；不过咱们都是出门做官的人，离别本是常事。只要四海之内有知心的朋友，哪怕相隔天涯，也会觉得像邻居一样亲近。咱们可不要在分手的路口，像小儿女那样哭哭啼啼、眼泪沾湿手帕呀。`, interpretation: `这是王勃二十岁不到时写给朋友杜少府的送别诗，地点在长安。诗人要去蜀地（四川）做官，王勃写诗为他送行。诗中有名句"海内存知己，天涯若比邻"，意思是真正的朋友即使远隔千山万水，心也贴得很近。这句诗之所以千古传唱，是因为它一扫送别诗里哭哭啼啼的愁绪，写得豪迈开朗、格局很大，把离别的伤感变成了友情的温暖。后人送别时常引用这两句，鼓励自己和朋友：天各一方，情谊不变。` }] },
  { id: 100, title: "滕王阁诗（节选）",
    author: "王勃",
    dynasty: "唐",
    category: "唐",
    summary: "落霞与孤鹜齐飞，秋水共长天一色",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "滕王阁诗（节选）", original: `滕王高阁临江渚，佩玉鸣鸾罢歌舞。
画栋朝飞南浦云，珠帘暮卷西山雨。
落霞与孤鹜齐飞，秋水共长天一色。`, translation: `滕王阁这座高高的楼阁，矗立在江边的小洲上。\n当年佩玉叮当、銮铃响彻的歌舞盛会，如今已经结束了。\n早晨，雕梁画栋间飘过南浦的白云；\n傍晚，珠串般的帘子卷起西山斜落的雨丝。\n天边的一抹晚霞与孤单的野鸭一起飞翔，\n秋天的江水和辽阔的天空融成了同一种颜色。`, interpretation: `这首诗写于唐朝初年，王勃二十多岁路过南昌，应朋友之邀在滕王阁上挥笔写下的。那时候的唐朝刚刚安定下来，文人们特别爱聚会、写诗。王勃用“南浦云”“西山雨”“落霞”“孤鹜”“秋水”“长天”这些画面，把秋天的傍晚写得又开阔又有点淡淡的感伤。特别是“落霞与孤鹜齐飞，秋水共长天一色”这两句，简直成了千古名句，连今天的语文课本都离不开它。后来很多人画画、写对联都要借用这两句，可见王勃有多厉害！` }] },
]
